INSERT INTO sub_areas (id, attraction_id, name_en, name_zh, body, cover_image_path, sort_order, is_active)
VALUES
  ('nanjing_1865_creative_park_sa_01', 'nanjing_1865_creative_park', 'The Old Main Gate', '老大门', 'The Old Main Gate dates back to 1865, when Li Hongzhang, then Viceroy of Liangjiang, petitioned the Qing court to establish the Jinling Machinery Manufacturing Bureau. Constructed with blue bricks and blending Chinese and Western architectural elements, the gate features a stone plaque above its lintel. It stands as a witness to the Self-Strengthening Movement and the dawn of China''s modern defense industry. Having weathered more than 150 years, the well-preserved gate is now the park''s most recognizable landmark, offering visitors a tangible link to the origins of Chinese modern industry.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_1865_creative_park_sa_01.jpg', 0),
  ('nanjing_1865_creative_park_sa_02', 'nanjing_1865_creative_park', 'Jinling Arsenal Exhibition Hall (Main Machinery Factory)', '金陵兵工展览馆（机器正厂）', 'Built in 1865 as the earliest core workshop of the Jinling Machinery Manufacturing Bureau, the Main Machinery Factory was used for firearms and artillery production. The building features a solid brick-and-timber structure with a pitched truss roof, exemplifying the localization of 19th-century Western industrial architecture in China. Renovated in 2010 and converted into the Jinling Arsenal Exhibition Hall, it displays weapons, machine tools, historical photographs, archival documents, and multimedia presentations that systematically trace the development of the Jinling Arsenal from the late Qing Self-Strengthening Movement through the Republican era. It is an essential window into the history of China''s modern defense industry.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_1865_creative_park_sa_02.jpg', 1),
  ('nanjing_1865_creative_park_sa_03', 'nanjing_1865_creative_park', 'Right Machinery Factory and Left Machinery Factory', '机器右厂与机器左厂', 'Constructed during the Tongzhi and Guangxu reigns of the Qing Dynasty, the Right and Left Machinery Factories flank the Main Machinery Factory in a symmetrical "one center, two wings" layout. They originally handled cartridge assembly and parts machining, with auxiliary workshops added as production expanded. The buildings feature load-bearing unplastered brick walls, large-span interior spaces, and arched windows for ventilation and natural light. After preservation-oriented renovations, the two historic factories now house cultural and creative enterprises, where century-old industrial spaces meet modern creative industries—a vivid emblem of the park''s transformation.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_1865_creative_park_sa_03.jpg', 2),
  ('nanjing_1865_creative_park_sa_04', 'nanjing_1865_creative_park', 'Yan Copper Factory and Juan Copper Factory', '炎铜厂与捲铜厂', 'Built in the late Qing Dynasty, the Yan Copper Factory and Juan Copper Factory were dedicated copper-processing workshops within the Jinling Machinery Manufacturing Bureau. The Yan Copper Factory melted and cast copper ingots at high temperatures, while the Juan Copper Factory rolled copper sheets into specified dimensions, supplying raw materials for cartridge cases and copper components. Though smaller than the Main Machinery Factory, the buildings retain remnants of original furnace foundations and rolling equipment. Soot marks on the brick walls silently attest to the fiery, bustling scenes of the past. Now preserved as industrial heritage, they reveal the complete supply chain of the modern arms industry.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_1865_creative_park_sa_04.jpg', 3),
  ('nanjing_1865_creative_park_sa_05', 'nanjing_1865_creative_park', 'Wood Factory Building and Large Machinery Factory', '木厂大楼与机器大厂', 'The Wood Factory Building and Large Machinery Factory are the two largest production building complexes in the Jinling Machinery Manufacturing Bureau. The Wood Factory Building originally manufactured gunstocks and wooden components, featuring a brick-and-timber structure with high ceilings and spacious interiors to accommodate lumber storage and processing equipment. The Large Machinery Factory handled forging and precision machining of heavy components, supported by a steel-framed roof structure—an advanced industrial building typology of its time. Both buildings are striking in appearance, with red brick walls and grey-tiled roofs. After renovation, they now serve as creative office and exhibition spaces, with original beams and columns retained so visitors can experience the spatial grandeur of 19th-century industrial architecture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_1865_creative_park_sa_05.jpg', 4),
  ('nanjing_1865_creative_park_sa_06', 'nanjing_1865_creative_park', 'Republic of China Office Building and Sawtooth Factory', '民国办公楼与锯齿形厂房', 'The Republic of China Office Building, constructed in the 1920s–1930s, is a two-story brick-and-concrete structure with a symmetrical facade, arched windows and doors, Western-style moldings, and an entrance portico. Its dignified and elegant style typifies Republican-era public architecture. The Sawtooth Factory, built in the same period, features a continuous sawtooth roof with north-facing glazing on each tooth—a European industrial design that admits even north light while avoiding direct sunlight that could affect precision work. The undulating sawtooth silhouette has become the park''s most recognizable skyline. Together, the two buildings document the modernization and expansion of the Jinling Arsenal during the Republican era and now serve as corporate offices and art exhibition spaces.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_1865_creative_park_sa_06.jpg', 5),
  ('nanjing_1865_creative_park_sa_07', 'nanjing_1865_creative_park', 'Anti-War Sculpture', '反战雕塑', 'Standing in the park''s green space, the Anti-War Sculpture is one of the most thought-provoking public artworks in the Chengguang 1865 Park. Through abstract sculptural language, it expresses themes of anti-war and peace, combining imagery such as fractured shell casings, interlaced arms, and doves to symbolize reflection on war and a call for peace. The work resonates with the site''s history as an arms production base—weapons manufactured here a century ago served war, while the same land now proclaims peace through art. Surrounded by trees in a tranquil setting, it has become a popular spot for visitors to pause, reflect, and photograph, embodying the spiritual core of the park.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_1865_creative_park_sa_07.jpg', 6),
  ('nanjing_1865_creative_park_sa_08', 'nanjing_1865_creative_park', 'Bronze Buddha Hand Statue', '佛手青铜像', 'The Bronze Buddha Hand Statue is placed in the park''s landscape area, a large-scale bronze sculpture cast in the form of a Buddhist mudra (hand gesture). The fingers are gently curved with the palm facing upward in the abhaya mudra ("gesture of fearlessness"), symbolizing the dispelling of fear and the granting of peace. The sculpture is grand in scale and elegant in form, its bronze surface specially treated to present an antique patina that contrasts yet harmonizes with the surrounding red-brick factory buildings. Its installation reflects the park''s cultural consciousness in transforming from military industry to creative culture, while also expressing a deep aspiration for peace. In morning light and evening glow, the Buddha Hand exudes solemnity and serenity, adding a touch of Zen and philosophical contemplation to the park.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_1865_creative_park_sa_08.jpg', 7),
  ('nanjing_1865_creative_park_sa_09', 'nanjing_1865_creative_park', 'Central Square and 1865 Digital Sculpture', '中央广场与1865数字雕塑', 'Located at the geographic center of the park, the Central Square is the hub for visitor circulation, cultural events, and public gatherings. Paved with granite and open in scale, it is surrounded by renovated historic factories and modern buildings, showcasing the park''s planning philosophy of "balanced preservation and adaptive reuse." At its center stands the "1865" numerical sculpture—four large metal digits in modern abstract form commemorating the founding year of the Jinling Machinery Manufacturing Bureau (1865, the fourth year of the Tongzhi reign). The sculpture''s mirror-finish stainless steel surface reflects the sky and surrounding old factory buildings by day, and glows under illumination at night, making it the park''s most iconic landmark and the most popular photo backdrop for visitors.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_1865_creative_park_sa_09.jpg', 8),
  ('nanjing_confucius_temple_qinhuai_sa_01', 'nanjing_confucius_temple_qinhuai', 'Ancient Qinhuai Archway (Entrance Plaza)', '古秦淮牌坊（入口广场）', 'The Ancient Qinhuai Archway stands at the southern entrance of the Fuzimiao scenic area, serving as the first landmark when entering the Qinhuai riverfront district. It is a four-column, three-bay soaring stone archway constructed of bluestone and white marble. The front lintel bears the gilded characters "Gu Qinhuai" (Ancient Qinhuai), while the reverse reads "Fuzimiao" (Confucius Temple), both in vigorous calligraphy. Stone lions guard either side, lending the structure a commanding presence. The entrance plaza before the archway is broad and flat, serving as a primary gathering and photo spot. During holidays, the plaza teems with visitors, and the archway glows brilliantly under illumination. Looking northward from here, one takes in the full panorama of the bustling riverside streets and historic architecture, marking the formal start of a Fuzimiao visit.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_confucius_temple_qinhuai_sa_01.jpg', 0),
  ('nanjing_confucius_temple_qinhuai_sa_02', 'nanjing_confucius_temple_qinhuai', 'Screen Wall and Pan Pool', '照壁与泮池', 'The Screen Wall, located on the south side of the Fuzimiao plaza along the north bank of the Qinhuai River, was first built in the Wanli reign of the Ming Dynasty. At approximately 110 meters in length, it is one of the longest surviving screen walls in China. Constructed of blue brick with a glazed-tile crown, its center features a relief carving of two dragons playing with a pearl, symbolizing literary prosperity. In front of the wall lies the Pan Pool, a semi-circular basin unique to Confucian temple complexes. The Nanjing Fuzimiao''s Pan Pool uniquely incorporates the natural Qinhuai River channel as the pool itself—a rare design among Confucian temples nationwide. Stone balustrades with finely carved panels line the pool. At dusk, the illuminated screen wall reflects in the water alongside passing painted boats, creating Fuzimiao''s most iconic nightscape.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_confucius_temple_qinhuai_sa_02.jpg', 1),
  ('nanjing_confucius_temple_qinhuai_sa_03', 'nanjing_confucius_temple_qinhuai', '"Greatest Center of Learning" Archway and Juxing Pavilion', '天下文枢坊与聚星亭', 'The "Greatest Center of Learning" Archway stands at the heart of the Fuzimiao plaza. This four-column, three-bay wooden archway bears the inscription "Tianxia Wenshu" ("Greatest Center of Learning Under Heaven") on its front and "Dongnan Diyi Xue" ("Foremost School of the Southeast") on its reverse, proclaiming the exalted status of Nanjing''s Confucius Temple as a center of Chinese culture and education. With upturned eaves, painted bracket sets, and a commanding presence, the archway is flanked by the Juxing Pavilion, a hexagonal double-eaved pavilion whose name means "Gathering of Stars," symbolizing the assembly of literary talents. The pavilion was historically a meeting place for scholars to discuss literature and ideas. Its delicate form complements the grand archway in a harmonious contrast of scales, together forming the most ceremonial spatial node of the temple''s front area and a classic photo spot.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_confucius_temple_qinhuai_sa_03.jpg', 2),
  ('nanjing_confucius_temple_qinhuai_sa_04', 'nanjing_confucius_temple_qinhuai', 'Lingxing Gate', '棂星门', 'The Lingxing Gate is a key node along the central axis of the Fuzimiao complex, positioned before the Dacheng Gate. "Lingxing" refers to the celestial field star; ancients sacrificed to it to pray for abundant harvests, and its presence at a Confucian temple signifies honoring Confucius as one honors Heaven. The gate takes the form of a three-bay, four-column stone archway, with carved stone beasts atop the pillars, cloud-and-dragon reliefs on the lintels, and monolithic granite columns. Stone steps and a ceremonial path flank the gate; in ancient times, all civil and military officials were required to dismount and proceed on foot as a mark of reverence for Confucius. As a distinctive architectural symbol of Confucian temples, the Lingxing Gate serves both ritual and symbolic functions, marking the critical transition from secular to sacred space and setting the stage for the grand sequence of the Dacheng Gate and Dacheng Hall beyond.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_confucius_temple_qinhuai_sa_04.jpg', 3),
  ('nanjing_confucius_temple_qinhuai_sa_05', 'nanjing_confucius_temple_qinhuai', 'Dacheng Gate', '大成门', 'Also known as the Halberd Gate, the Dacheng Gate is the formal entrance to the core building complex of the Confucius Temple. Its name derives from Mencius''s description of Confucius as one who "achieved the grand synthesis" (ji dacheng). The gate has a five-bay facade, a single-eave hip-and-gable roof with yellow glazed tiles, painted bracket sets, and door panels studded with nails and door knockers. Originally, halberd-bearing guardian figures flanked the entrance, giving rise to the alternative name. Normally only the central portal is opened; all three doors are opened together only during major ceremonies. Stone steles from the Ming and Qing dynasties line the flanking paths, recording temple renovations and ritual protocols. Crossing the high threshold, one enters the temple''s core ritual courtyard, where ancient cypresses and rows of stone tablets transform the atmosphere from worldly bustle to solemn reverence.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_confucius_temple_qinhuai_sa_05.jpg', 4),
  ('nanjing_confucius_temple_qinhuai_sa_06', 'nanjing_confucius_temple_qinhuai', 'Dacheng Hall', '大成殿', 'The Dacheng Hall is the centerpiece and soul of the Confucius Temple complex. First built in the first year of the Jingyou reign of the Northern Song Dynasty (1034), it was destroyed and rebuilt multiple times; the current structure was reconstructed in 1984 following Qing Dynasty specifications. The hall has a seven-bay facade, a double-eave hip-and-gable roof with yellow glazed tiles, and rises approximately 18 meters high. Inside, a seated statue of Confucius—about 4.5 meters tall—occupies the center, flanked by the Four Correlates (Yan Hui, Zengzi, Zisi, and Mencius) and the Twelve Wise Disciples, all fashioned in traditional painted clay. Thirty-eight mosaic murals depicting Confucius''s life are displayed within, crafted with exquisite inlay work. The broad terrace before the hall was historically the site of grand Confucian sacrifice ceremonies, with a bronze incense burner at its center. Imperial plaques, including the Kangxi Emperor''s calligraphy "Teacher of Ten Thousand Generations," hang from the beams, creating an overwhelming atmosphere of solemnity—this is the essential place to experience the majesty and reverence of Confucian culture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_confucius_temple_qinhuai_sa_06.jpg', 5),
  ('nanjing_confucius_temple_qinhuai_sa_07', 'nanjing_confucius_temple_qinhuai', 'Mingde Hall, Zunjing Pavilion, and Southeast''s No.1 School', '明德堂、尊经阁与东南第一学', 'Mingde Hall, Zunjing Pavilion, and the "Southeast''s No.1 School" comprise the academy section of the Confucius Temple complex, located behind the Dacheng Hall. Mingde Hall is the main building of the academy, named after the concept of "illustrating virtue" from The Great Learning, and served as a lecture hall in ancient times. It now displays imperial examination artifacts and classical Confucian texts. Zunjing Pavilion, a two-story building behind Mingde Hall, was originally a library housing Confucian classics and imperially bestowed books, ranking among the most prestigious structures in the academy. The plaque "Southeast''s No.1 School" hangs at the academy entrance, proclaiming the preeminence of the Fuzimiao academy in the regional educational system. The three structures align along the central axis in ascending sequence, forming the integrated "temple-and-academy" layout. Visitors here can gain insight into the ancient Chinese system of combining temple and school, and the transmission of Confucian culture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_confucius_temple_qinhuai_sa_07.jpg', 6),
  ('nanjing_confucius_temple_qinhuai_sa_08', 'nanjing_confucius_temple_qinhuai', 'Jiangnan Imperial Examination Hall (South Branch of China Imperial Examination Museum)', '江南贡院（中国科举博物馆南馆）', 'First established in the fourth year of the Qiandao reign of the Southern Song Dynasty (1168), the Jiangnan Imperial Examination Hall was continuously expanded through the Ming and Qing dynasties. At its zenith, it contained over 20,000 examination cells, making it the largest provincial examination venue in the Qing Dynasty. During each autumn examination, more than 20,000 candidates gathered here to endure nine days of testing across three sessions in cells of less than two square meters each—the most spectacular scene in the history of Chinese imperial examinations. In 2012, the China Imperial Examination Museum was built on this site. The South Branch preserves the historical layout and surviving structures of the Qing Dynasty examination hall, including reconstructed cells, the Dragon Gate, and archways, vividly recreating the examination experience through artifacts and immersive scenes. Walking through, visitors can deeply appreciate the hardship of "ten years of cold-window study" and the glory of "having one''s name on the golden roll."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_confucius_temple_qinhuai_sa_08.jpg', 7),
  ('nanjing_confucius_temple_qinhuai_sa_09', 'nanjing_confucius_temple_qinhuai', 'China Imperial Examination Museum (North Branch) and Mingyuan Tower', '中国科举博物馆（北馆）与明远楼', 'Opened in 2014, the North Branch of the China Imperial Examination Museum is China''s only underground museum dedicated to the imperial examination system. Resembling a "scholar''s treasure box" buried underground, the museum descends approximately 20 meters below ground level. The visitor route spirals downward along a ramp, progressively presenting the history, examination content, regulations, and profound social and cultural impact of the imperial examination system. The collection comprises over 10,000 artifacts, including examination papers, cheat sheets, plaques, and champion''s robes. Mingyuan Tower stands at the museum''s ground-level entrance, originally built during the Jiajing reign of the Ming Dynasty as the sole surviving structure of the Jiangnan Examination Hall. It once served as a surveillance tower for exam proctors, its three-story, four-sided eaved silhouette now an iconic landmark of the Fuzimiao area. The underground museum and the above-ground tower form a dialogue across time, offering the most comprehensive showcase of China''s imperial examination culture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_confucius_temple_qinhuai_sa_09.jpg', 8),
  ('nanjing_confucius_temple_qinhuai_sa_10', 'nanjing_confucius_temple_qinhuai', 'Wende Bridge', '文德桥', 'Originally built in the Wanli reign of the Ming Dynasty, Wende Bridge spans the Qinhuai River to the west of the Fuzimiao Pan Pool, serving as a vital link between the Confucius Temple and Wuyi Alley on the south bank. The name "Wende" means "literary virtue," resonating with Confucian culture. The bridge is most famous for the "Half Moon at Wende Bridge" phenomenon: according to legend, at midnight on the fifteenth day of the eleventh lunar month, viewers standing at a specific spot on the bridge can see the moon''s reflection split in half—one half visible on each side of the bridge. This extraordinary optical effect inspired countless poems and literary works, ranking alongside the West Lake''s Three Pools Mirroring the Moon. The stone arch bridge features balustrades carved with cloud and lotus motifs. Today, Wende Bridge offers one of the finest vantage points for the Qinhuai nightscape, where illuminated lanterns and passing painted boats create a scene that is an essential part of any Fuzimiao visit.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_confucius_temple_qinhuai_sa_10.jpg', 9),
  ('nanjing_confucius_temple_qinhuai_sa_11', 'nanjing_confucius_temple_qinhuai', 'Wuyi Alley and Wang-Xie Ancient Residence', '乌衣巷与王谢古居', 'Located on the south bank of the Qinhuai River near Fuzimiao, Wuyi Alley is one of Nanjing''s oldest lanes, with a history traceable to the Eastern Wu Kingdom of the Three Kingdoms period. During the Eastern Jin Dynasty, the Wang Dao and Xie An clans—two of the most powerful aristocratic families—resided here, and the alley was named for the dark robes ("wu yi") worn by their family members. The Tang Dynasty poet Liu Yuxi immortalized the alley with his famous lines: "Swallows that once nested before the halls of Wang and Xie, now fly into the homes of common folk," making it one of the most culturally evocative lanes in Chinese literary history. The Wang-Xie Ancient Residence within the alley is a memorial exhibition hall that uses Six Dynasties artifacts, genealogies, calligraphy, paintings, and reconstructed living scenes to showcase the contributions of the Wang and Xie families to the politics and culture of the Eastern Jin and Southern Dynasties. Built in the style of Six Dynasties residences, the hall features elegant layouts of reception rooms, studies, and courtyards that recreate the lifestyle of the era''s noble families.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_confucius_temple_qinhuai_sa_11.jpg', 10),
  ('nanjing_confucius_temple_qinhuai_sa_12', 'nanjing_confucius_temple_qinhuai', 'Qinhuai Painted Boat Wharf (Cruise Experience)', '秦淮画舫码头（游船体验）', 'The Qinhuai Painted Boat Wharf is located beside the Fuzimiao Pan Pool, serving as the primary boarding point for Qinhuai River cruises. The painted boats (huafang) are traditional vessels unique to the Qinhuai River, featuring colorfully painted and carved hulls, red lanterns suspended from canopies, and cabins furnished with tables, chairs, and tea service in classical style. The cruise route covers the most scenic stretch of the Qinhuai River, passing Bailu Islet, Zhonghua Gate, and Taoye Ferry, with the full journey lasting approximately 50 minutes. Daytime cruises offer views of historic architecture and weeping willows along both banks, but the evening is the true highlight—brilliantly illuminated banks reflect shimmering light on the water, accompanied by the sound of traditional string and bamboo music from the bow, evoking the romantic imagery of Zhu Ziqing''s celebrated essay "Splashing Oars and Lamp Shadows on the Qinhuai River." Drifting slowly between centuries-old bridges and riverside pavilions, the painted boat offers the most immersive way to experience Nanjing''s Qinhuai culture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_confucius_temple_qinhuai_sa_12.jpg', 11),
  ('nanjing_ganxi_mansion_sa_01', 'nanjing_ganxi_mansion', 'South Gate (Main Entrance)', '南门（正门）', 'The South Gate serves as the formal entrance to the entire architectural complex. Featuring three bays in width, it exhibits the traditional Nanjing style with grey bricks and dark tiles. The lintel bears exquisite brick carvings, while the high threshold reflects the social status of a Qing Dynasty gentry family. A screen wall once stood before the gate but no longer survives. The original stone door frame and pillow stones remain intact, their carvings simple yet dignified. Passing through this gate, visitors officially enter the renowned Qing Dynasty residential complex known as "Ninety-Nine and a Half Rooms."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ganxi_mansion_sa_01.jpg', 0),
  ('nanjing_ganxi_mansion_sa_02', 'nanjing_ganxi_mansion', 'Entrance Hall and Sedan Chair Hall', '门厅与轿厅', 'The Entrance Hall and Sedan Chair Hall constitute the first courtyard of the residence. The entrance hall, three bays wide and relatively shallow in depth, was primarily used for receiving and registering visitors. Beyond its courtyard lies the sedan chair hall, which as the name suggests served as a parking space for sedan chairs and a waiting area. The two halls are separated by a flagstone-paved courtyard with concealed drainage channels, embodying the traditional feng shui concept of "four waters returning to the hall." Historical photographs of the Gan family and exhibition panels introducing the residence''s history are currently displayed in the entrance hall.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ganxi_mansion_sa_02.jpg', 1),
  ('nanjing_ganxi_mansion_sa_03', 'nanjing_ganxi_mansion', 'Yougong Hall (Main Hall)', '友恭堂（正厅）', 'Yougong Hall is the main hall of the Ganxi Former Residence and the highest-ranking courtyard in the complex. It spans five bays with a post-and-lintel structure, featuring fine materials and sturdy beams and columns. The hall''s name "Yougong" derives from the Book of Documents, meaning "brotherly love and respectful conduct," reflecting the Gan family''s philosophy of household management. A calligraphic name plaque hangs at the center, and traditional furnishings including an Eight Immortals table and grandmaster chairs are arranged according to Qing Dynasty gentry protocols. This hall was used for receiving distinguished guests, holding family councils, and conducting weddings, funerals, and other important ceremonies, making it a vital window into the life of a prominent Nanjing family.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ganxi_mansion_sa_03.jpg', 2),
  ('nanjing_ganxi_mansion_sa_04', 'nanjing_ganxi_mansion', 'Inner Hall and Echo Hall', '内厅与响厅', 'Located behind the main hall, the Inner Hall was the daily living and guest-receiving space for the women of the Gan family. Though slightly smaller in scale than the main hall, it is more finely decorated, with original Qing Dynasty wood carvings on brackets and lattice doors and windows. Adjacent to the Inner Hall, the Echo Hall is one of the most ingenious features of the residence. Ceramic resonating chambers are built beneath its floor, producing a crisp echo when someone walks across, serving both as a burglar alarm and a ceremonial announcement system. This design is extremely rare among Nanjing''s traditional residences, fully demonstrating the architectural wisdom of Qing Dynasty craftsmen, and remains one of the most popular interactive experiences for visitors.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ganxi_mansion_sa_04.jpg', 3),
  ('nanjing_ganxi_mansion_sa_05', 'nanjing_ganxi_mansion', 'Running Horse Building', '跑马楼', 'The Running Horse Building is the most distinctive residential structure in the Ganxi Former Residence. It features a two-story layout with verandas connecting all four sides, allowing occupants to walk a complete circuit on the upper floor without turning back — resembling a galloping horse, hence the name. This architectural form is uncommon among Jiangnan residences and primarily served to enable family members to move between rooms during inclement weather. The wooden railings are adorned with exquisite carvings of bats, ruyi scepters, and other auspicious motifs symbolizing longevity and good fortune. The floors are connected by wooden staircases, whose handrails still bear the wear marks of generations of daily use by the Gan family.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ganxi_mansion_sa_05.jpg', 4),
  ('nanjing_ganxi_mansion_sa_06', 'nanjing_ganxi_mansion', 'Study and Side Alley', '书房与备弄', 'The Study, located on the west side of the central axis, offers a tranquil setting and served as the dedicated space for the Gan family''s children to study, compose poetry, and paint. The room is furnished with a writing desk, brush stand, inkstone, and other stationery items, with calligraphy and paintings by generations of Gan family members hanging on the walls. Adjacent to the Study, the Side Alley is a narrow north-south passage wide enough for only one person, flanked by high walls, connecting the courtyards laterally. In traditional residences, the side alley played a vital role: on ordinary days it allowed servants to move about without disturbing the family, while during fires it served as a firebreak and emergency evacuation route — an indispensable functional space in Nanjing''s traditional residential architecture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ganxi_mansion_sa_06.jpg', 5),
  ('nanjing_ganxi_mansion_sa_07', 'nanjing_ganxi_mansion', 'Back Garden (Small Garden) and Tingqiu Pavilion', '后花园（小园）与听秋阁', 'The Back Garden, also known as the Small Garden, is situated at the northernmost end of the residence and served as the Gan family''s private retreat. Though modest in area, the garden is ingeniously laid out with rockeries, water features, and abundant plantings including osmanthus, wintersweet, and banana trees, offering scenic views in every season. Tingqiu Pavilion, a two-story structure within the garden, takes its name from the idea of "quietly listening to the sounds of autumn." From its upper floor, visitors can overlook the entire garden. When osmanthus blooms in autumn, enjoying tea and fragrance within the pavilion while listening to the wind and admiring the moon is most delightful. Though not as grand as Suzhou gardens, this garden is celebrated for its ability to suggest vastness within a small space and stands as a typical example of Nanjing''s private residential gardens.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ganxi_mansion_sa_07.jpg', 6),
  ('nanjing_ganxi_mansion_sa_08', 'nanjing_ganxi_mansion', 'Jindai Tower', '津逮楼', 'Jindai Tower is one of the most culturally significant buildings in the Ganxi Former Residence, serving as the Gan family''s private library, built in the mid-Qing Dynasty. The literary Gan family amassed over 100,000 volumes at its peak, spanning classics, histories, philosophy, and literature, with particular strength in local documents and rare editions — rivaling the famous Tianyi Pavilion in Ningbo. The tower''s name "Jindai" means "reachable ford," a metaphor for books as the bridge to knowledge. The original structure was destroyed during the Taiping Rebellion, and the current building is a reconstruction based on historical records. Inside, replicas of the Gan family''s ancient books and exhibits on the culture of book collecting are displayed, telling the story of a family''s enduring dedication to cultural preservation.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ganxi_mansion_sa_08.jpg', 7),
  ('nanjing_ganxi_mansion_sa_09', 'nanjing_ganxi_mansion', 'Wangyue Tower and Yan Fengying''s Former Residence', '望月楼与严凤英旧居', 'Wangyue Tower, located on the east side of the residence, is a two-story building with windows on all four sides offering expansive views — an ideal spot for the Gan family to admire the moon during the Mid-Autumn Festival or climb for views during the Double Ninth Festival. The interior is simply and elegantly furnished, preserving the original appearance of a Qing Dynasty residence. Adjacent to the tower is the Former Residence of Yan Fengying (1930–1968), the legendary Huangmei Opera performer who married into the Gan family and lived here for many years. The residence displays precious artifacts including her biographical materials, performance photographs, opera costumes, and personal belongings, recreating the life of this great artist in Nanjing and adding a layer of artistic legend to the Ganxi Former Residence.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ganxi_mansion_sa_09.jpg', 8),
  ('nanjing_ganxi_mansion_sa_10', 'nanjing_ganxi_mansion', 'Jinling Eighteen Workshops and Intangible Cultural Heritage Exhibition Area', '金陵十八坊与非遗展区', 'The Jinling Eighteen Workshops and Intangible Cultural Heritage Exhibition Area is the most vibrant interactive space within the residence. The original Eighteen Workshops were a cluster of handicraft workshops in Nanjing''s southern city during the Ming and Qing Dynasties. Here, scene reconstructions recreate the authentic atmosphere of traditional workshops for velvet flowers, cloud brocade, lantern-making, and paper-cutting. The heritage exhibition area showcases Nanjing''s intangible cultural heritage projects at or above the municipal level, including Yunjin brocade weaving, Jinling sutra printing, and the Qinhuai Lantern Festival. Some projects feature live craft demonstrations where visitors can observe the exquisite skills of heritage inheritors up close and even try certain crafts themselves, experiencing the living charm of traditional culture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ganxi_mansion_sa_10.jpg', 9),
  ('nanjing_ganxi_mansion_sa_11', 'nanjing_ganxi_mansion', 'Old Nanjing Folk Customs Exhibition Area', '老南京民俗展区', 'The Old Nanjing Folk Customs Exhibition Area is located in the final courtyard of the residence, combining scene reconstructions with artifact displays to comprehensively present the daily life and folk culture of Nanjing residents during the late Qing and early Republican periods. The exhibition covers themes including wedding customs, festivals, child-rearing, clothing, and food, displaying a large collection of folk artifacts such as bridal sedans, dowries, antique furniture, traditional cooking utensils, and seasonal items. The "Nanjing Wedding Customs" section, featuring a bridal sedan, phoenix coronet, and dragon-and-phoenix curtains, recreates the full traditional wedding procession and is particularly captivating. Miniature models of old Nanjing street scenes vividly recreate the bustling life along the Qinhuai River, making this an excellent destination for understanding Nanjing''s local folk culture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ganxi_mansion_sa_11.jpg', 10),
  ('nanjing_laomendong_sa_01', 'nanjing_laomendong', 'Men Dong Archway', '门东牌坊', 'The Men Dong Archway is the principal entrance landmark of the Lao Men Dong Historical and Cultural Block, situated at the northern end of the block. The archway follows a traditional stone structure imitating timber construction, with a four-pillar, three-bay, three-roof layout, built of bluestone and topped with gray tiles. The central plaque bears the three characters "Lao Men Dong," while the flanking pillars are inscribed with couplets in vigorous, archaic calligraphy. The overall design is dignified and graceful, continuing the architectural conventions of traditional Nanjing archways while incorporating the refined aesthetics of Jiangnan gardens. As the gateway to the block, the archway is the first visual focal point for visitors and a popular landmark for photographs, bearing the cultural symbolism of the revitalization of Nanjing''s historic southern district.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_laomendong_sa_01.jpg', 0),
  ('nanjing_laomendong_sa_02', 'nanjing_laomendong', 'Gutong Alley', '箍桶巷', 'Gutong Alley is a centuries-old lane within the Lao Men Dong Historical and Cultural Block, named after the large number of barrel-making craftsmen who gathered here during the Ming and Qing dynasties. "Gutong" refers to the traditional craft of making wooden barrels by joining wooden staves and securing them with iron hoops—an indispensable trade in the daily life of old Nanjing''s southern district. Along both sides of the alley are several preserved and restored traditional residential buildings, featuring whitewashed walls, dark tiles, and prominent horse-head gables, exhibiting the typical architectural style of Jiangnan folk dwellings. Today, Gutong Alley serves as a main pedestrian route of the block, lined with specialty restaurants, creative shops, and intangible cultural heritage exhibition spaces, organically integrating historical character with modern commerce, making it an excellent destination for experiencing the urban folk culture of southern Nanjing.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_laomendong_sa_02.jpg', 1),
  ('nanjing_laomendong_sa_03', 'nanjing_laomendong', 'Street Sculpture Group', '街头雕塑群', 'The Street Sculpture Group is scattered throughout the alleys and squares of the Lao Men Dong block, realistically recreating the diverse scenes of everyday life in old Nanjing''s southern district. The sculptures cover a wide range of subjects, including peddlers carrying shoulder poles and hawking goods, craftsmen mending pots and bowls, elderly people gathered around chess games, and children playing with shuttlecocks and jump ropes. All are cast in bronze, with vivid and expressive figures and meticulous attention to detail. These sculptures complement the traditional architectural environment of the block, adding rich cultural charm to the historic district and serving as popular photo spots for visitor interaction. More than mere art installations, the sculpture group constitutes a three-dimensional illustrated guide to Nanjing folk culture, allowing visitors to directly experience the vibrant atmosphere and cultural memories of the old southern district while strolling through the block.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_laomendong_sa_03.jpg', 2),
  ('nanjing_laomendong_sa_04', 'nanjing_laomendong', 'Santiao Ying and Jiang Shoushan''s Former Residence', '三条营与蒋寿山故居', 'Santiao Ying is a relatively well-preserved historic alley within the Lao Men Dong block, named after the military camps stationed here during the Ming and Qing dynasties. The alley contains several restored and protected traditional residential courtyards. The Former Residence of Jiang Shoushan, located within Santiao Ying, was the residence of Jiang Shoushan, a prominent Huizhou merchant in Qing-era Nanjing. The building faces south with a multi-courtyard progressive layout, featuring an exquisitely ornate brick-carved gate tower and well-preserved wooden structural frames, representing a typical example of traditional residential architecture in the Nanjing area. The residence now serves as a cultural exhibition space open to the public. Together, Santiao Ying and the Jiang Shoushan Residence form the core historic and cultural area of the Lao Men Dong block, providing an important window into understanding the residential architecture and mercantile culture of southern Nanjing.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_laomendong_sa_04.jpg', 3),
  ('nanjing_laomendong_sa_05', 'nanjing_laomendong', 'Jianzi Alley and Jinling Art Museum', '剪子巷与金陵美术馆', 'Jianzi Alley is a historic lane within the Lao Men Dong block, named after the numerous scissor-making workshops that gathered here during the Ming and Qing dynasties, bearing witness to the prosperity of old Nanjing''s handicraft industry. Traditional residential buildings line both sides of the alley, with blue bricks, gray tiles, and a serene, rustic atmosphere. The Jinling Art Museum, located within Jianzi Alley, was converted from the former Nanjing Color Weaving Factory, ingeniously blending industrial heritage with modern design language. The museum primarily showcases contemporary art, encompassing painting, sculpture, installation, video, and other art forms, and regularly hosts domestic and international art exhibitions and public education programs. The historical charm of Jianzi Alley and the artistic vitality of the Jinling Art Museum complement each other, making it a landmark space where traditional culture and modern art converse within the Lao Men Dong block.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_laomendong_sa_05.jpg', 4),
  ('nanjing_laomendong_sa_06', 'nanjing_laomendong', 'Shangjiang Examination Hall', '上江考棚', 'The Shangjiang Examination Hall is a historic site of profound imperial examination cultural significance within the Lao Men Dong block. During the Qing dynasty, Nanjing housed the Jiangnan Examination Hall, the largest provincial examination venue in the nation, and the Shangjiang Examination Hall served as the preparation and lodging facility for candidates from Anhui Province ("Shangjiang" refers to Anhui) traveling to Nanjing for examinations. The site preserves partial building foundations and historical stone inscriptions, and after restoration, it has been opened to the public as an imperial examination culture exhibition space. Exhibitions cover the evolution of the ancient examination system, reconstructions of examination hall regulations, and displays of examination-related artifacts, systematically introducing the historical development and social impact of the imperial examination system through combined illustrative panels and physical displays. The Shangjiang Examination Hall is an important physical witness to Nanjing''s role as a center of imperial examination culture and a significant reflection of the cultural depth of the Lao Men Dong block.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_laomendong_sa_06.jpg', 5),
  ('nanjing_laomendong_sa_07', 'nanjing_laomendong', 'Fu Shanxiang''s Former Residence', '傅善祥旧居', 'The Former Residence of Fu Shanxiang is a historic building within the Lao Men Dong block closely associated with a legendary woman. Fu Shanxiang (1833—1856), a native of Nanjing, participated in the women''s imperial examination during the Taiping Heavenly Kingdom period and was appointed as the female top scholar for her outstanding talent, becoming the only female top scholar in Chinese history. The residence is a traditional courtyard-style folk dwelling, featuring blue brick walls, small gray tiles, and wooden doors and windows, with a compact and elegant layout, embodying the typical characteristics of middle-class residences in southern Nanjing. After restoration and preservation, the building is now open to the public with an exhibition themed on Fu Shanxiang''s life and deeds. Through historical documents, photographs, and scene reconstructions, it tells the legendary story of this female top scholar who served as a female secretary in the Taiping Heavenly Kingdom government and participated in political affairs, showcasing the unique life of an extraordinary woman who pursued knowledge and ideals in turbulent times.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_laomendong_sa_07.jpg', 6),
  ('nanjing_laomendong_sa_08', 'nanjing_laomendong', 'Jiezi Garden', '芥子园', 'Jiezi Garden is the private garden built in Nanjing by Li Yu (1611—1680), a renowned literatus and dramatist of the Ming-Qing transition period. Named after the Buddhist concept of "a mustard seed containing Mount Sumeru," it symbolizes seeing the infinite within the finite—the cosmos within a small space. Although the original garden no longer exists, the present Jiezi Garden was reconstructed near the original site within the Lao Men Dong block. The garden features rockery arrangements, water features, pavilions, corridors, and terraces, employing refined landscaping techniques to create the illusion of vast natural scenery within a compact space, fully embodying Li Yu''s aesthetic philosophy of garden design. The garden houses a Li Yu cultural exhibition introducing his achievements in literature, drama, garden design, and publishing. Though modest in size, Jiezi Garden offers richly layered scenery that shifts with every step, making it an important destination for understanding classical Chinese garden art and Li Yu''s cultural legacy.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_laomendong_sa_08.jpg', 7),
  ('nanjing_laomendong_sa_09', 'nanjing_laomendong', 'Yao Nai''s Former Residence (Xibaoxuan)', '姚鼐故居（惜抱轩）', 'Yao Nai''s Former Residence (Xibaoxuan) is an important cultural celebrity residence within the Lao Men Dong block. Yao Nai (1732—1815), courtesy name Jichuan, was a renowned prose master and scholar of the Qing dynasty and the synthesizer of the Tongcheng School. His study was named "Xibaoxuan," hence he was known as "Master Xibao." The residence is a traditional courtyard-style building, facing south with a brick-and-wood structure, featuring a tranquil and elegant courtyard with lush plants, embodying the typical character of a Qing dynasty literati dwelling. Yao Nai presided over the Zhongshan Academy in Nanjing for decades, making outstanding contributions to the city''s educational and cultural enterprises. The residence houses an exhibition on Yao Nai and Tongcheng School culture, displaying his writings, academic achievements, and the lineage of the Tongcheng School literary tradition. This is an important place to experience the atmosphere of Qing dynasty scholarly culture and understand the literary principles of the Tongcheng School.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_laomendong_sa_09.jpg', 8),
  ('nanjing_laomendong_sa_10', 'nanjing_laomendong', 'Ming City Wall (Lao Men Dong Section)', '明城墙（老门东段）', 'The Ming City Wall (Lao Men Dong Section) is an important component of the Nanjing Ming City Wall. Construction of the Nanjing Ming City Wall began in the twenty-sixth year of the Zhizheng era of the Yuan dynasty (1366) and took over twenty years to complete, making it one of the largest and best-preserved ancient city walls in the world. The Lao Men Dong section extends along the southern side of the block, built with massive stone block foundations and brick masonry, towering and majestic, still standing firm after more than six hundred years. This section features pedestrian stairs allowing visitors to ascend the wall and enjoy panoramic views of the whitewashed walls and dark-tiled traditional buildings of the Lao Men Dong block and the southern city, as well as distant views of Purple Mountain, Yuhuatai, and other urban landmarks. The wall itself is the most direct witness to Nanjing''s urban history, and together with the Lao Men Dong historic block, constitutes the most profoundly rich historical and cultural landscape of southern Nanjing.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_laomendong_sa_10.jpg', 9),
  ('nanjing_city_wall_sa_01', 'nanjing_city_wall', 'Zhonghua Gate Square (Entrance)', '中华门广场（入口）', 'Zhonghua Gate Square is located on the south side of the Nanjing City Wall at Zhonghua Gate, serving as the starting point for visitors entering the barbican scenic area. The square is broad and flat, extending approximately 100 meters from north to south. Looking up, visitors can see the majestic city wall spanning before them, reaching up to 21 meters in height with a commanding presence. A guide stele stands at the center of the square, with ticket booths and a visitor service center on either side. Ginkgo and sycamore trees line the square; in autumn, their golden foliage contrasts beautifully with the grey wall. This is also the best vantage point for photographing the full frontal view of Zhonghua Gate, and many iconic images of Nanjing have been captured here.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_city_wall_sa_01.jpg', 0),
  ('nanjing_city_wall_sa_02', 'nanjing_city_wall', 'First City Gate (Main Gate)', '第一道城门（主城门）', 'The First City Gate is the main south-facing gate of the Zhonghua Gate barbican and the largest gate in the entire defensive system. The gate arch is a vaulted structure approximately 10 meters high and 6 meters wide, accommodating both carriages and horses. Inside the arch, slots for a heavy portcullis are visible, which could be lowered during wartime to seal the passage. The base of the flanking walls is built with massive stone blocks, topped with brick masonry. Inscriptions on the bricks — recording their place of manufacture and the names of the craftsmen — remain clearly legible, serving as important physical evidence for the study of the Ming Dynasty brick production system. Passing through this gate, visitors enter the first barbican and experience the military ingenuity of the "catching turtles in a jar" defensive design.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_city_wall_sa_02.jpg', 1),
  ('nanjing_city_wall_sa_03', 'nanjing_city_wall', 'First Barbican', '第一道瓮城', 'The First Barbican is the outermost of the three barbicans at Zhonghua Gate, covering approximately 3,700 square meters. Visitors enter this space after passing through the main gate. Walls flank it to the east and west, with the second gate to the north, forming a semi-enclosed courtyard on three sides. The core tactical concept of the barbican is to "lure the enemy in deep and catch them like turtles in a jar" — if enemy forces breach the main gate and rush into the barbican, defenders can seal the gates front and rear, then attack from above with arrows, rolling stones, and firearms from all four sides, making escape impossible. The interior is flat and was historically used for stationing troops. Today, multiple exhibition panels introduce the history, construction techniques, and successive renovations of Zhonghua Gate.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_city_wall_sa_03.jpg', 2),
  ('nanjing_city_wall_sa_04', 'nanjing_city_wall', 'Soldier-Hiding Caverns', '藏兵洞', 'The Soldier-Hiding Caverns are the most distinctive military feature of Zhonghua Gate. Built into the interior of the barbican walls, there are 27 chambers arranged across multiple levels. Each chamber ranges from 20 to 60 square meters in area, with vaulted ceilings, good ventilation, and concealed entrances that are virtually undetectable from outside the wall. According to historical records, the caverns could garrison over 3,000 soldiers in peacetime and accommodate more than 10,000 during wartime, while storing large quantities of grain, weapons, and drinking water sufficient for prolonged defensive operations. The chambers are warm in winter and cool in summer. Today, some have been converted into exhibition spaces displaying Ming Dynasty weapons, inscribed bricks, and reconstructed models of defensive equipment, vividly recreating the military scene from six centuries ago.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_city_wall_sa_04.jpg', 3),
  ('nanjing_city_wall_sa_05', 'nanjing_city_wall', 'Horse Ramp', '马道', 'The Horse Ramp is a stone-paved inclined passage built into the interior side of the Zhonghua Gate city wall, approximately 5 meters wide. Paved with stone slabs, it winds from the base of the wall up to the top. During wartime, cavalry could ride directly up the ramp, transporting arrows, rolling stones, grain, and other supplies to defensive positions along the wall crest, greatly enhancing the mobility of the defense. Two ramps are provided on the east and west sides of Zhonghua Gate as backups, ensuring that if one is destroyed, the other remains passable. The ramp has a gradient of approximately 15 to 20 degrees, with low parapet walls on both sides. Walking along it, visitors can appreciate both the practical design of the military architecture and the imposing mass of the wall from a lateral perspective. Today, most visitors use the horse ramp to ascend the wall, making it the best route for experiencing the grandeur of the structure.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_city_wall_sa_05.jpg', 4),
  ('nanjing_city_wall_sa_06', 'nanjing_city_wall', 'Wall Crest', '城墙顶部', 'The wall crest is the highest point of the Zhonghua Gate scenic area, approximately 21 meters high, with a top width of 4 to 5 meters paved with smooth bricks, allowing several people to walk abreast. From the top, visitors can gaze northward to see the Qinhuai River meandering through the city and the white-walled, dark-tiled buildings of the Confucius Temple area; southward, the verdant pines and cypresses of Yuhuatai stretch to the horizon; eastward, the Zifeng Tower and Purple Mountain echo each other in a blend of ancient and modern. The wall is topped with crenellations (battlements), with merlons every few steps for soldiers to shoot from and take cover behind. Several reconstructed Ming Dynasty defensive devices and the remains of sentry posts are preserved on the crest. Climbing the wall at dusk, when the setting sun illuminates the ancient bricks, is the golden hour for photographing the Nanjing skyline.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_city_wall_sa_06.jpg', 5),
  ('nanjing_city_wall_sa_07', 'nanjing_city_wall', 'Nanjing City Wall Museum', '南京城墙博物馆', 'The Nanjing City Wall Museum, located just east of Zhonghua Gate, is China''s only museum dedicated to the theme of city walls. It opened in 2013 with a permanent exhibition titled "A Magnificent Wall," organized into chapters including "Heaven and Earth in Harmony: The Capital of the Great Ming," "Every Brick and Tile: United Will Builds the Wall," and "Six Centuries of Wind and Rain: The Vicissitudes of the Wall." Through artifacts, architectural models, multimedia interactives, and holographic projections, the museum systematically presents the planning, design philosophy, construction techniques, and historical evolution of the Nanjing Ming Dynasty City Wall. The museum houses a large collection of inscribed bricks, each bearing the names of the prefecture, county, and craftsman who produced it — precious evidence of the Ming Dynasty''s "inscribe the workman''s name" quality accountability system. Admission is free, making it an essential stop for anyone seeking to deeply understand the culture of the Nanjing City Wall.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_city_wall_sa_07.jpg', 6),
  ('nanjing_city_wall_sa_08', 'nanjing_city_wall', 'Taicheng Section (Premium Segment)', '台城段（精华段）', 'The Taicheng Section is the most representative premium segment of the Nanjing Ming Dynasty City Wall, located on the northeast stretch from Xuanwu Gate to Taiping Gate, approximately 5 kilometers in length. This segment is built along Mount Jilong (Beiji Pavilion), standing on elevated terrain. To the north, it overlooks the vast blue waters of Xuanwu Lake; to the south, it adjoins the millennia-old Jiming Temple. The wall, lake, mountains, and temple pagoda create a dazzling interplay that forms Nanjing''s most iconic cityscape. The name "Taicheng" derives from the Palace City of the Six Dynasties period; though not directly related to the Ming wall, this section was named for its proximity to the former Taicheng site. The wall top can be explored on foot or by bicycle, with multiple viewing platforms and rest stations along the way. Ascending Taicheng to gaze at the majestic Purple Mountain and the vast Xuanwu Lake is the ultimate way to experience Nanjing''s urban layout of "mountains, water, city, and forest."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_city_wall_sa_08.jpg', 7),
  ('nanjing_ming_xiaoling_sa_01', 'nanjing_ming_xiaoling', 'Xiama Fang Heritage Park', '下马坊遗址公园', 'Built in 1393 during the Hongwu reign, the Xiama Fang (Dismount Archway) is the landmark entrance to Ming Xiaoling Mausoleum. Its lintel bears the imperial edict "All Officials Dismount Here." According to Ming court protocol, officials of every rank had to dismount and walk from this point forward as a gesture of respect for Zhu Yuanzhang, the founding emperor of the Ming Dynasty. The original archway was destroyed in wartime and later restored from surviving Ming-era remnants. The surrounding area has been developed into a tranquil heritage park with ancient trees, marking it as both the starting point of the sacred way and the first encounter with Ming imperial funerary etiquette.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ming_xiaoling_sa_01.jpg', 0),
  ('nanjing_ming_xiaoling_sa_02', 'nanjing_ming_xiaoling', 'Da Jin Men (Great Golden Gate)', '大金门', 'Constructed during the Hongwu reign, Da Jin Men is the first formal palace gate of the Ming Xiaoling Mausoleum complex and marks the southern origin of the entire mausoleum''s central north-south axis. The gate was built with large imperial bricks and originally topped with yellow glazed roof tiles. It features three parallel archways: the central passage was reserved for the emperor''s and empress''s coffins, while the side passages were used by civil and military officials. Da Jin Men''s architectural format pioneered the "gate-before-hall" layout that became standard for all subsequent Ming and Qing imperial mausoleums, profoundly influencing the design of the Thirteen Ming Tombs in Beijing and the Eastern and Western Qing Tombs. It stands as a milestone in the history of Chinese imperial funerary architecture.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ming_xiaoling_sa_02.jpg', 1),
  ('nanjing_ming_xiaoling_sa_03', 'nanjing_ming_xiaoling', 'Si Fang Cheng (Square City / Pavilion of Divine Merits and Sacred Virtues)', '四方城（神功圣德碑亭）', 'Originally named the "Pavilion of Divine Merits and Sacred Virtues," Si Fang Cheng earned its popular name "Square City" from its square plan and fortress-like walls. Inside stands the "Stele of Divine Merits and Sacred Virtues of Ming Xiaoling," personally composed by Emperor Yongle (Zhu Di) in 1413. The inscription, comprising 2,746 characters, recounts the life and achievements of Zhu Yuanzhang and ranks among the largest merit steles in ancient China. The pavilion originally featured a double-eaved hip-and-gable roof with yellow glazed tiles of imposing scale. The roof collapsed during the Taiping Rebellion, yet the four walls still stand majestically today. The brickwork is fitted without visible mortar, showcasing an extraordinary level of craftsmanship that evokes the grandeur of Ming imperial construction.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ming_xiaoling_sa_03.jpg', 2),
  ('nanjing_ming_xiaoling_sa_04', 'nanjing_ming_xiaoling', 'Shi Xiang Lu Sacred Way (Stone Elephant Road)', '石象路神道', 'Shi Xiang Lu is the first segment of the Ming Xiaoling Mausoleum sacred way, stretching approximately 615 meters. Twelve pairs of stone animals — lions, xiezhi (mythical justice beasts), camels, elephants, qilin, and horses — line both sides in sequence, with each species represented by one standing pair and one kneeling pair, totaling twenty-four sculptures. Each was carved from a single monolithic stone block in the round, combining monumental scale with rustic yet lifelike modeling. These beasts symbolize the imperial guard of honor, auspiciousness, and loyalty. In autumn, golden ginkgoes and fiery maples arch over the path, framing the ancient stone animals in a dazzling canopy of color. This scene has earned the road the affectionate title "The Most Beautiful 600 Meters in Nanjing," offering visitors a perfect fusion of Ming stone carving artistry and natural beauty.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ming_xiaoling_sa_04.jpg', 3),
  ('nanjing_ming_xiaoling_sa_05', 'nanjing_ming_xiaoling', 'Weng Zhong Lu Sacred Way (Weng Zhong Road)', '翁仲路神道', 'Weng Zhong Lu is the second segment of the Ming Xiaoling Mausoleum sacred way, extending approximately 250 meters northward from Shi Xiang Lu. Two pairs of military generals and two pairs of civil officials — eight statues in total — flank the path, each carved from a single stone block. The generals, clad in armor and wielding swords, project martial authority; the civil officials, wearing court caps and holding ceremonial tablets, exude dignified composure. The name "Weng Zhong" traces back to Ruan Weng Zhong of the Qin Dynasty, whose name later became a generic term for guardian stone figures at tombs. The statues are imposing in scale and exquisitely carved — every fold of drapery and scale of armor is crisply rendered — representing the pinnacle of Ming imperial stone sculpture. They symbolize the eternal vigilance of the emperor''s civil and military retinue guarding his eternal rest.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ming_xiaoling_sa_05.jpg', 4),
  ('nanjing_ming_xiaoling_sa_06', 'nanjing_ming_xiaoling', 'Ling Xing Men and Jin Shui Qiao (Lingxing Gate and Golden Water Bridge)', '棂星门与金水桥', 'Ling Xing Men originally served as the ceremonial gateway at the terminus of the Ming Xiaoling Mausoleum sacred way. It featured three parallel passages with cloud-and-dragon carvings atop the pillars. The name "Lingxing" refers to the celestial field star, symbolizing reverence for heaven and ancestors. The original gate was destroyed in wartime and has been reconstructed based on archaeological findings. Beyond the gate lies the Jin Shui Qiao (Golden Water Bridge), a group of stone bridges spanning the inner Golden Water River. Originally five in number, three survive today. Built of grey limestone, the bridges are simple and elegant in form. The Golden Water River is an integral element of the mausoleum''s drainage system and feng shui layout. North of the bridge stands the Wen Wu Fang Gate, beyond which lies the core palace complex of the mausoleum. Together, the Lingxing Gate and Golden Water Bridge form the pivotal transitional point from the sacred way to the mausoleum palace proper, both functionally and symbolically.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ming_xiaoling_sa_06.jpg', 5),
  ('nanjing_ming_xiaoling_sa_07', 'nanjing_ming_xiaoling', 'Wen Wu Fang Men (Gate of Civil and Military Officials)', '文武方门', 'Wen Wu Fang Men is the first formal gate of the Ming Xiaoling Mausoleum''s core palace complex. It spans five bays in width and two in depth, with a single-eaved hip-and-gable roof covered in yellow glazed tiles. A plaque reading "Ming Xiaoling Mausoleum" was originally suspended above the entrance. According to Ming sacrificial protocol, during major ceremonies held on Qingming, Zhongyuan, and Winter Solstice, civil and military officials were required to assemble in ranked formation outside this gate before being admitted to perform rites — hence the name "Gate of Civil and Military Officials." The gate has three archways, with the central passage reserved exclusively for the emperor''s and empress''s coffins and sacrificial objects. Two side gates on the east and west provided daily access. The architecture is solemn and hierarchically precise, serving as the dividing line between the external sacred way and the internal sacrificial precinct. It occupies a pivotal linking position along the mausoleum''s central axis.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ming_xiaoling_sa_07.jpg', 6),
  ('nanjing_ming_xiaoling_sa_08', 'nanjing_ming_xiaoling', 'Bei Dian (Stele Hall / "Zhi Long Tang Song" Stele)', '碑殿（治隆唐宋碑）', 'The Stele Hall sits between Wen Wu Fang Men and the Sacrificial Hall. At its center stands the famous "Zhi Long Tang Song" stele, bearing the calligraphy of Emperor Kangxi of the Qing Dynasty, inscribed during his third southern inspection tour in 1699. The four characters mean "Governance Surpassing Tang and Song," declaring that Zhu Yuanzhang''s achievements in statecraft exceeded those of Emperor Taizong of Tang and Emperor Taizu of Song. This expressed Kangxi''s profound admiration for the Ming founding emperor while also serving the political purpose of winning the hearts of Han Chinese scholars and commoners in the Jiangnan region. The stele is crowned with a carved dragon head and rests on a bixi (mythical tortoise) base, reflecting its exalted status. The hall also preserves poetic steles and inscriptions left by Emperor Qianlong and other Qing monarchs during their southern tours, making it a vital material witness to the political and cultural interactions between the Ming and Qing dynasties.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ming_xiaoling_sa_08.jpg', 7),
  ('nanjing_ming_xiaoling_sa_09', 'nanjing_ming_xiaoling', 'Xiang Dian Yi Zhi (Ruins of the Sacrificial Hall)', '享殿遗址', 'Originally named "Xiaoling Hall," the Sacrificial Hall was the architectural and functional centerpiece of the Ming Xiaoling Mausoleum palace complex, serving as the principal venue for grand sacrificial ceremonies. The original hall spanned nine bays in width and five in depth, with a double-eaved hipped roof sheathed in yellow glazed tiles. It housed the spirit tablets of Zhu Yuanzhang and Empress Ma and was comparable in scale to the Hall of Supreme Harmony in the Forbidden City. Tragically, the hall was destroyed during the Taiping Rebellion. What remains today is a three-tiered stone sumeru plinth foundation with fifty-six massive column bases, along with scattered architectural elements such as stone dragon-head water spouts. A smaller hall, rebuilt during the Tongzhi reign of the Qing Dynasty, stands in front of the original foundation. Though modest in comparison, it continues to host annual sacrificial rites and now displays historical photographs and excavated artifacts related to the mausoleum.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ming_xiaoling_sa_09.jpg', 8),
  ('nanjing_ming_xiaoling_sa_10', 'nanjing_ming_xiaoling', 'Fang Cheng Ming Lou (Square City and Ming Tower)', '方城明楼', 'Fang Cheng Ming Lou is the last above-ground structure on the central axis of Ming Xiaoling Mausoleum and one of the most innovative designs in Chinese imperial funerary architecture. The "Square City" is a rectangular brick-and-stone platform approximately 16 meters tall, its base constructed from massive cut-stone blocks and its upper portion of stacked imperial bricks, rising fortress-like above the surrounding terrain. A vaulted tunnel runs through the center of the platform, its walls lined with stone lamp niches, creating a deep and solemn passageway. Above the south entrance to the tunnel, seven characters are carved: "This Mountain Is the Tomb of Ming Taizu," directly pointing toward the burial mound. The Ming Tower, originally a double-eaved hip-and-gable timber structure, was destroyed during the Taiping Rebellion and faithfully reconstructed in 2008–2009 based on Ming-era specifications. From its upper gallery, visitors can gaze across the layered ridges of Purple Mountain, taking in a sweeping panorama of cypress-covered slopes and the full grandeur of the mausoleum precinct.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ming_xiaoling_sa_10.jpg', 9),
  ('nanjing_ming_xiaoling_sa_11', 'nanjing_ming_xiaoling', 'Bao Ding (Treasure Peak)', '宝顶', 'Bao Ding is the spiritual heart of Ming Xiaoling Mausoleum — the burial mound of Zhu Yuanzhang and Empress Ma (Empress Xiaoci Gao), situated directly behind the Fang Cheng Ming Lou. It is an enormous circular rammed-earth tumulus approximately 400 meters in diameter and 1,000 meters in circumference, built by layering yellow earth and crushed stone, then encased in a retaining wall of imperial bricks. Ancient pines and cypresses crown the mound in perpetual green, giving it the appearance of a lush hill when viewed from afar. A stone wall at the southern edge bears the carved inscription "This Mountain Is the Tomb of Ming Taizu," identifying the tomb''s location for later generations. For over six centuries, the underground palace of Ming Xiaoling has never been archaeologically excavated, making it one of the few intact and undisturbed imperial tombs in Chinese history. In 2003, it was inscribed on the UNESCO World Heritage List as an extension of the "Imperial Tombs of the Ming and Qing Dynasties."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_ming_xiaoling_sa_11.jpg', 10),
  ('nanjing_museum_sa_01', 'nanjing_museum', 'Main Entrance and History Hall', '正门与历史馆大殿', 'The predecessor of Nanjing Museum was the National Central Museum, proposed in 1933 by Cai Yuanpei and others — the first large-scale comprehensive museum in China built with government funding. The History Hall''s grand hall was designed by the eminent architect Xu Jingzhi, with Liang Sicheng serving as consultant. The building emulates the architectural style of the Liao Dynasty, spanning nine bays with a single-eaved hipped roof. It is a landmark work of the "traditional revival" movement in modern Chinese architectural history. The hall now serves as the main entrance to the History Gallery. Approaching through the front plaza, visitors are greeted by a striking interplay of glazed flying eaves and vermillion columns — solemn yet elegant. This is the first stop of any Nanjing Museum visit and the starting point for appreciating the century-long journey of China''s modern museum enterprise.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_museum_sa_01.jpg', 0),
  ('nanjing_museum_sa_02', 'nanjing_museum', 'History Gallery · 2F Hall 1 — Ancient Impressions', '历史馆·2楼1号厅——远古印象', 'Located in Hall 1 on the second floor of the History Gallery, "Ancient Impressions" is the opening chapter of Nanjing Museum''s permanent exhibition "Ancient Civilization of Jiangsu," focusing on the geological evolution and ancient life of the Jiangsu region. The hall displays a rich collection of paleontological fossils unearthed in Jiangsu, most notably large dinosaur skeletal specimens — including tyrannosauroid and sauropod dinosaurs — whose massive bones and dynamic postures recreate the spectacular scenes of the Mesozoic era when dinosaurs dominated the land. Also on view are fossils of trilobites, ammonites, and ancient fish, supplemented by stratigraphic cross-section models and geological time-scale charts that help visitors build a macro-level understanding of how the land of Jiangsu was transformed from ocean to continent across deep time.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_museum_sa_02.jpg', 1),
  ('nanjing_museum_sa_03', 'nanjing_museum', 'History Gallery · 2F Hall 2 — Prehistoric Charm and the Wu-Yue Spring and Autumn Period', '历史馆·2楼2号厅——史前神韵与吴越春秋', 'Located in Hall 2 on the second floor, this exhibition traces the historical evolution of the Jiangsu region from the Paleolithic era through the Spring and Autumn and Warring States periods. The hall assembles jade, pottery, and stone artifacts excavated from major Neolithic sites, including the Beiyinyangying, Qingliangang, and Liangzhu cultures. Ritual jades such as cong tubes and bi discs display remarkable craftsmanship, reflecting the religious concepts and aesthetic consciousness of early civilizations. During the Spring and Autumn and Warring States periods, Jiangsu was at the crossroads of the states of Wu and Yue. Exhibited bronze weapons of Wu, bronze ritual vessels of Yue, and the precious "Sword of King Fuchai of Wu" recreate the epic rivalry between these two ancient powers. Organized along archaeological findings, the gallery weaves a magnificent narrative of Jiangsu''s transformation from wilderness to civilization.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_museum_sa_03.jpg', 2),
  ('nanjing_museum_sa_04', 'nanjing_museum', 'History Gallery · 2F Hall 3 — The Han Homeland', '历史馆·2楼3号厅——汉家故里', 'Located in Hall 3 on the second floor, "The Han Homeland" centers on archaeological discoveries from the Xuzhou region, showcasing the prosperity and splendor of northern Jiangsu during the Western and Eastern Han Dynasties. The most iconic exhibit is the silver-threaded jade burial suit unearthed from the tomb of a Chu king of the Western Han Dynasty, composed of over 2,000 jade plaques laced together with silver wire. Its craftsmanship is extraordinary, and it ranks among the most complete jade suits ever discovered in China. The hall also features an impressive array of Han Dynasty pictorial stones, painted pottery figurines, bronze vessels, and gold artifacts. The pictorial stones, carved in relief, depict mythological legends, historical tales, and scenes of daily life with rich content and vigorous lines — often called "epics in stone." The Han practice of lavish burial and the philosophy of "treating death as life" are vividly embodied in these remarkable artifacts.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_museum_sa_04.jpg', 3),
  ('nanjing_museum_sa_05', 'nanjing_museum', 'History Gallery · 1F Hall 4 — Splendor of the Six Dynasties', '历史馆·1楼4号厅——六朝风华', 'Located in Hall 4 on the first floor, "Splendor of the Six Dynasties" focuses on the period from the third to the sixth century, when six successive dynasties — Eastern Wu, Eastern Jin, Liu Song, Southern Qi, Liang, and Chen — established their capitals in Nanjing (ancient Jiankang). Despite frequent political upheavals, this era saw the flourishing of Jiangnan culture. The exhibition centers on Yue kiln celadon wares, including chicken-head ewers, lotus-petal vases, and spittoons, their glazes verdant and lustrous — representing the pinnacle of porcelain craftsmanship of the time. Also displayed are pottery figurines, bronze mirrors, gold and silver ornaments, and epitaphs excavated from Six Dynasties tombs. The human figurines are remarkably expressive, with finely detailed attire reflecting the aesthetic sensibilities and daily life of the era. The profound heritage of Nanjing as the "Ancient Capital of Six Dynasties" is presented here in a concentrated and captivating display.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_museum_sa_05.jpg', 4),
  ('nanjing_museum_sa_06', 'nanjing_museum', 'History Gallery · 1F Halls 5–6 — Jiangnan Prosperity', '历史馆·1楼5-6号厅——江南盛世', 'Located in Halls 5 and 6 on the first floor, "Jiangnan Prosperity" presents the glorious history of the Jiangsu region as the economic and cultural center of China from the Sui and Tang dynasties through the Ming and Qing. Since the opening of the Sui-Tang Grand Canal, Jiangnan gradually became the nation''s granary and fiscal heartland, reaching its zenith during the Song, Yuan, Ming, and Qing. The exhibition follows a narrative thread from artifacts unearthed at the Tang-era Yangzhou city site, through Ming Dynasty imperial objects from Nanjing, to Qing-era crafts from Suzhou. On display are goldware, jade, silk, porcelain, lacquerware, and the Four Treasures of the Study. Particularly noteworthy are architectural components from Ming Xiaoling Mausoleum, a Ming Dynasty gold crown, and Qing Dynasty enamelware. Scene reconstructions and multimedia presentations recreate historical vistas such as Yangzhou salt merchants'' gardens and Suzhou streetscapes, offering a panoramic view of Jiangnan''s wealth and refinement as the "paradise on earth."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_museum_sa_06.jpg', 5),
  ('nanjing_museum_sa_07', 'nanjing_museum', 'Special Exhibition Hall', '特展馆', 'The Special Exhibition Hall is a standalone, modernized exhibition space on the east side of the Nanjing Museum complex, dedicated to hosting temporary and traveling exhibitions. It contains several flexibly partitioned galleries equipped with climate-controlled display cases, professional lighting, and multimedia presentation systems, meeting international first-class exhibition standards. The hall regularly introduces fine exhibitions from domestic and international museums, covering diverse themes such as calligraphy and painting, porcelain, jade, bronze, Buddhist art, and world civilizations. It has hosted blockbuster exhibitions including "Pharaoh and King," "Mucha," and "Three Masters of the Renaissance." Each visit offers new surprises, making it an ideal platform for experiencing the global cultural pulse and the frontiers of art.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_museum_sa_07.jpg', 6),
  ('nanjing_museum_sa_08', 'nanjing_museum', 'Digital Hall', '数字馆', 'Located on the underground level of Nanjing Museum, the Digital Hall is one of the earliest purpose-built digital exhibition spaces in a Chinese museum. It employs cutting-edge technologies — including 3D projection, virtual reality, interactive sensing, and holographic imaging — to present the museum''s collection and historical scenes in entirely new ways. Inside, a giant curved screen plays a spectacular panorama of Jiangsu''s historical civilization, while floor-based interactive projections allow visitors to "step" out ripples and blossoms. A virtual reconstruction of the Six Dynasties capital Jiankang comes to life onscreen with stunning realism. Visitors can also use touchscreens to rotate and zoom in on 3D artifact models, examining every detail from any angle. The Digital Hall breaks down the barriers of traditional display cases, making history tangible and sensory — an experience especially beloved by younger audiences.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_museum_sa_08.jpg', 7),
  ('nanjing_museum_sa_09', 'nanjing_museum', 'Republic of China Hall', '民国馆', 'Located on the underground level of Nanjing Museum, the Republic of China Hall is a full-scale, 1:1 recreation of a Nanjing street from the Republican era. Stepping inside, visitors are instantly transported to the 1930s capital: along cobblestone streets lined with period buildings — a post office, bank, pharmacy, photo studio, bookstore, tailor shop, and train station — signage and advertisements faithfully reproduce the original designs of old Republican-era brands. Vintage mailboxes, rickshaws, retro streetlamps, and even a projected sky overhead have been meticulously designed to create a remarkably convincing sense of temporal immersion. The post office sells postcards with Republican-era scenery that can be mailed on-site, the train station features a vintage steam locomotive, and the bookstore stocks reproduced period publications. The Republic of China Hall is not merely an exhibition but a tactile, participatory historical experience.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_museum_sa_09.jpg', 8),
  ('nanjing_museum_sa_10', 'nanjing_museum', 'Art Gallery', '艺术馆', 'The Art Gallery is located along the central axis of the Nanjing Museum complex, serving as the dedicated venue for displaying the museum''s finest art collections. It houses thematic galleries including the Historical Painting Gallery, Historical Calligraphy Gallery, Sculpture Gallery, Fu Baoshi Art Gallery, and Chen Zhifo Art Gallery, systematically presenting the development of Chinese art from ancient to modern times. The Painting Gallery exhibits masterworks from the Song, Yuan, Ming, and Qing dynasties, including representative works of the Four Masters of the Ming, the Four Wangs of the Early Qing, and the Eight Eccentrics of Yangzhou. The Calligraphy Gallery assembles ink treasures by masters across the ages in all major script styles. The Fu Baoshi Art Gallery is dedicated to the New Jinling School master''s landscape paintings and seal carvings, characterized by their sweeping grandeur. The Chen Zhifo Art Gallery displays his exquisite gongbi flower-and-bird paintings, elegant and refined. The Art Gallery also regularly hosts contemporary art exhibitions and academic events, serving as an important platform for dialogue between traditional and contemporary art.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_museum_sa_10.jpg', 9),
  ('nanjing_museum_sa_11', 'nanjing_museum', 'Intangible Cultural Heritage Hall (Jiangsu Provincial Intangible Cultural Heritage Museum)', '非遗馆（江苏省非物质文化遗产馆）', 'The Intangible Cultural Heritage Hall, officially named the Jiangsu Provincial Intangible Cultural Heritage Museum, is one of the first dedicated intangible heritage exhibition spaces established within a provincial-level museum in China. Its core philosophy is living heritage display, combining physical exhibits, scene reconstructions, live demonstrations, and interactive experiences to present representative items from Jiangsu''s national and provincial intangible cultural heritage lists. Exhibits encompass dozens of heritage categories, including Kunqu Opera, the guqin zither, Nanjing Yunjin brocade hand-weaving techniques, Suzhou embroidery, Yixing purple clay pottery, Yangzhou lacquerware, and Nantong blue calico. A dedicated demonstration area hosts intangible heritage inheritors performing live craft demonstrations — visitors can observe Yunjin brocade weaving, purple clay shaping, and embroidery stitching up close. Hands-on activities such as rubbings and paper-cutting allow visitors to personally experience the warmth and artisanship of intangible cultural heritage.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_museum_sa_11.jpg', 10),
  ('nanjing_massacre_memorial_sa_01', 'nanjing_massacre_memorial', 'Sculpture Plaza', '雕塑广场', 'The Sculpture Plaza serves as the prologue to the memorial hall''s visiting sequence, featuring large-scale bronze sculptures created by renowned sculptor Wu Weishan. The sculptures include "Broken Family, Dead People," "Fleeing," and "Screaming Souls," with the tallest reaching twelve meters in height. Crafted in a rugged and solemn style, they depict scenes such as a mother holding her deceased infant and civilians fleeing in panic, recreating the profound suffering of the Chinese people during the 1937 Nanjing Massacre. The sculptures integrate seamlessly with the architectural environment, silently conveying the weight of history and inspiring visitors to cherish peace and reverence for life.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_massacre_memorial_sa_01.jpg', 0),
  ('nanjing_massacre_memorial_sa_02', 'nanjing_massacre_memorial', 'Public Memorial Square', '公祭广场', 'The Public Memorial Square is the core square of the memorial hall and the venue for the annual National Memorial Ceremony for the Victims of the Nanjing Massacre held on December 13. At its center stands a cross-shaped marker inscribed with "1937.12.13—1938.1," reminding visitors never to forget that tragic history. The square is paved with gray granite, and its surrounding walls bear the numeral "300,000" in commemoration of the three hundred thousand compatriots who perished in the massacre. The expansive and solemn space can accommodate ten thousand people for memorial ceremonies. The predominantly gray-and-white architecture creates a somber and tragic atmosphere, making it an essential site for collective mourning and remembrance.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_massacre_memorial_sa_02.jpg', 1),
  ('nanjing_massacre_memorial_sa_03', 'nanjing_massacre_memorial', 'Historical Materials Exhibition Hall', '史料陈列厅', 'The Historical Materials Exhibition Hall is the principal exhibition space of the memorial hall. Organized chronologically, it systematically presents the complete history of the Japanese army''s occupation of Nanjing in 1937 and the implementation of the massacre. The hall displays a large number of precious historical artifacts, including Japanese military maps, weapons and equipment, victims'' belongings, video testimonies of survivors, correspondence archives of international friends, and trial records from the International Military Tribunal for the Far East. The exhibition employs diverse methods—physical displays, document exhibitions, multimedia presentations, and scene reconstructions—to present historical truth from multiple perspectives. The hall also features a victims'' name wall and a survivors'' archive database, providing irreplaceable documentary support for historical research.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_massacre_memorial_sa_03.jpg', 2),
  ('nanjing_massacre_memorial_sa_04', 'nanjing_massacre_memorial', '"Ten Thousand Bodies Pit" Site', '"万人坑"遗址', 'The "Ten Thousand Bodies Pit" Site is the most profoundly shocking area of the memorial hall. In 1984, a large number of victims'' remains from the Nanjing Massacre were excavated here, and forensic examinations confirmed they all resulted from unnatural deaths. The site is preserved in situ, covered with a glass floor through which visitors can clearly see the densely layered remains. The bones are distributed in varying postures, some bearing clear marks of violent death, providing irrefutable evidence of the Japanese army''s mass killings. Adjacent to the site is a remains display room, complemented by archaeological excavation records and forensic reports, preserving this tragic history with indisputable physical evidence and warning future generations never to forget national humiliation.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_massacre_memorial_sa_04.jpg', 3),
  ('nanjing_massacre_memorial_sa_05', 'nanjing_massacre_memorial', 'Cemetery Square', '墓地广场', 'The Cemetery Square is an important mourning space within the memorial hall''s visiting sequence, using architectural language to create a cemetery-like atmosphere of solemnity. At the center of the square stands a symbolic tomb, representing the collective burial and eternal remembrance of the perished compatriots. The tomb wall is constructed of black granite, inscribed with the names of identified victims, a list that continues to be expanded. Both sides of the square are paved with cobblestones, barren of vegetation, symbolizing the desolation of death and the passing of lives. Visitors pause here in silent tribute, gazing at the names on the wall, sensing the once-living individuals behind each name. With minimalist architectural vocabulary, the square expresses profound grief and is one of the most moving spaces in the memorial hall.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_massacre_memorial_sa_05.jpg', 4),
  ('nanjing_massacre_memorial_sa_06', 'nanjing_massacre_memorial', 'Memorial Ceremony Ground and Meditation Hall', '祭场与冥思厅', 'The Memorial Ceremony Ground is the core venue for mourning activities within the memorial hall, featuring an eternal flame and a flower-offering terrace where visitors may lay flowers to express their deep condolences for the perished compatriots. The eternal flame burns year-round, symbolizing the eternal remembrance of the deceased. The Meditation Hall, located behind the ceremony ground, is a semi-underground structure with dim interior lighting illuminated only by candlelight, creating a tranquil and profound atmosphere. A water-dripping device is installed inside, and the gentle sound of falling water drops echoes in the silent space, symbolizing the passage of time and the eternity of memory. Visitors slow their pace here, conversing with history in stillness and contemplating the preciousness of peace and the dignity of life.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_massacre_memorial_sa_06.jpg', 5),
  ('nanjing_massacre_memorial_sa_07', 'nanjing_massacre_memorial', 'Peace Park', '和平公园', 'Peace Park is situated at the conclusion of the memorial hall''s visiting route, marking a thematic transition from painful history toward a peaceful future. The park features green vegetation and water surfaces as its primary landscape elements, forming a striking contrast with the preceding gray-and-white architectural palette, symbolizing the continuation of life and the rebirth of hope. The central feature is the "Peace" sculpture, depicting a mother holding an infant in one arm and releasing a dove of peace with the other, expressing the Chinese people''s aspiration and pursuit of peace. The park also features the Peace Spring, Peace Grove, and other landscape elements, with murmuring water and shaded trees, providing visitors with a space to soothe and settle their minds after departing from the heavy history, conveying the core concept of "remembering history and cherishing peace."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_massacre_memorial_sa_07.jpg', 6),
  ('nanjing_massacre_memorial_sa_08', 'nanjing_massacre_memorial', 'Wall of Victory and Victory Square', '胜利之墙与胜利广场', 'The Wall of Victory and Victory Square are important components of the memorial hall''s expansion project, officially opened in 2015 on the occasion of the seventieth anniversary of the victory of the Chinese People''s War of Resistance Against Japanese Aggression and the World Anti-Fascist War. The Wall of Victory presents a grand historical panorama in the form of large-scale reliefs, depicting the Chinese military and civilians fighting heroically and ultimately achieving victory. The reliefs vividly portray key scenes including battlefield charges, civilian support for the front lines, and Japan''s surrender. The Victory Square is expansive and dignified, capable of hosting large-scale memorial events, with victory-themed sculptures standing upon it. Centered on the theme of "victory," it forms a narrative progression from the preceding themes of "disaster" and "mourning," demonstrating the historical logic from suffering to triumph and highlighting the indomitable spirit of the Chinese nation.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_massacre_memorial_sa_08.jpg', 7),
  ('nanjing_massacre_memorial_sa_09', 'nanjing_massacre_memorial', '"Three Must-Wins" Theme Exhibition Hall', '"三个必胜"主题展厅', 'The "Three Must-Wins" Theme Exhibition Hall is one of the core pavilions of the memorial hall''s expansion project, themed on the important proposition put forward by General Secretary Xi Jinping: "Justice will prevail, Peace will prevail, and People will prevail." Through a wealth of historical artifacts, documentary archives, audiovisual materials, and multimedia presentations, the hall comprehensively reviews the glorious course of the Chinese People''s War of Resistance Against Japanese Aggression, highlighting the cornerstone role of the Communist Party of China during the war, the heroic deeds of the entire nation''s bloody struggle, and the great victory of the World Anti-Fascist War. The hall also presents post-war trials and the reconstruction of the international order, guiding visitors to profoundly understand the great significance of justice, peace, and the power of the people while remembering the tragic history, and to strengthen their commitment to safeguarding world peace.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_massacre_memorial_sa_09.jpg', 8),
  ('nanjing_niushoushan_sa_01', 'nanjing_niushoushan', 'Usnisa Front Garden', '佛顶前苑', 'Opened in 2018, the Usnisa Front Garden features approximately 100,000 square meters of natural landscapes and artistic installations, showcasing the profound multicultural heritage of Niushou Mountain. As a key passageway leading to the Usnisa Temple and the Usnisa Palace, the garden comprises fifteen scenic nodes, including the Liuli Glazed Mural Wall, Jixian Bridge, the Ten Oxen Herding Pictures rockery, Tingxin Lake, the Farong Square, and the Xinlian (Lotus Heart) Plaza. The scene unfolds in three visual layers—a foreground of dragonflies over red lotuses, a middle ground of mist drifting like a white silk band, and a distant view of temples merging with mountain hues—together forming a serene traditional ink-painting-like landscape. As the birthplace of the Niutou (Ox-Head) school of Chan Buddhism, Niushou Mountain''s deep Buddhist heritage is vividly presented through sculptures of Master Farong preaching to wild animals and a white marble wall inscribed with the "Xinming" (Inscription of Mind).', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_niushoushan_sa_01.jpg', 0),
  ('nanjing_niushoushan_sa_02', 'nanjing_niushoushan', 'Usnisa Temple', '佛顶寺', 'The Usnisa Temple is the core monastery of the Niushou Mountain Cultural Tourism Park, built in the traditional Tang dynasty seven-hall (Shichido Garan) layout with a grand and dignified architectural style imitating that of the Tang era. Situated on the southern foothills of Niushou Mountain''s East Peak and facing south, the temple complex is arranged along a central axis with the Mountain Gate, Heavenly Kings Hall, and Mahavira Hall, flanked symmetrically by a bell tower, drum tower, Guanyin Hall, and Ksitigarbha Hall. Covering over 30,000 square meters, the temple features spacious halls, sweeping eaves, and robust bracket sets that embody the spirit of High Tang Buddhist architecture. Beyond being a place of worship, the temple also houses monks'' quarters and a meditation hall that reveal the daily practice of Chan Buddhism, making it an ideal destination for visitors seeking spiritual tranquility.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_niushoushan_sa_02.jpg', 1),
  ('nanjing_niushoushan_sa_03', 'nanjing_niushoushan', 'Usnisa Palace (Exterior and Minor Dome)', '佛顶宫（外观与小穹顶）', 'The Usnisa Palace is the centerpiece of the Usnisa Sacred Realm, constructed within a massive abandoned iron-ore mining pit on the western peak of Niushou Mountain. Measuring 220 meters long, 160 meters wide, and 89.3 meters high, with a total floor area of approximately 136,000 square meters, the structure spans nine levels—three above ground and six below. The exterior is themed around "offering" and is divided into a Major Dome and a Minor Dome. The 120-meter Major Dome resembles the Buddha''s kasaya (monastic robe), draping over the Minor Dome below to symbolize the Buddha''s boundless blessing, while echoing Niushou Mountain''s East Peak across the valley. The Minor Dome takes the form of the Buddha''s usnisa (cranial protuberance), with each segment shaped like a pair of hands folded in prayer, representing the devotion of countless believers. The Minor Dome''s base forms a lotus throne composed of 56 Flying Apsara Bodhi Gates and 56 Cloud-Door Wish-Fulfilling Pillars, creating the sacred imagery of "a jewel supported by a lotus." From afar, the golden dome gleams against the green mountains, as if growing from the pit itself—a truly breathtaking sight.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_niushoushan_sa_03.jpg', 2),
  ('nanjing_niushoushan_sa_04', 'nanjing_niushoushan', 'Usnisa Palace · Zen Grand View', '佛顶宫·禅境大观', 'Located on the first above-ground level of the Usnisa Palace, the Zen Grand View (Chanjing Daguan) is the first major space visitors encounter upon entering. It spans 112 meters north to south, 62 meters east to west, with a total architectural height of 46.5 meters and an interior clearance of approximately 38 meters. The elliptical, vaulted hall covers over 6,000 square meters. Centered on Chan (Zen) culture, the space comprises three sections: the Zen Garden of the Buddha''s Birth, the Zen Garden of the Buddha''s Enlightenment, and the central Lotus Theater, together narrating the life story of Shakyamuni Buddha from birth to parinirvana. At the heart of the hall, a 7.5-meter-long reclining Buddha statue lies serenely upon a lotus stage. When no performance is underway, the lotus petals fold inward and the stage becomes an open public space. During performances, giant lotus leaves rise from below as the reclining Buddha slowly descends, accompanied by an interplay of sound, light, and visual effects, creating an otherworldly audiovisual spectacle that conveys the profound meaning of Buddhist "nirvana."', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_niushoushan_sa_04.jpg', 3),
  ('nanjing_niushoushan_sa_05', 'nanjing_niushoushan', 'Usnisa Palace · Relic Hall (Thousand Buddha Hall)', '佛顶宫·舍利大殿（千佛殿）', 'The Relic Hall, also known as the Thousand Buddha Hall, is situated on the fifth underground level of the Usnisa Palace and serves as the core space for enshrining the Buddha''s usnisa bone relic. The hall features a vaulted, elliptical plan with a color palette of red, gold, and dark gold, exuding solemn grandeur. At its center rises a 21.8-meter-tall relic pagoda, cast entirely in bronze and inlaid with the Buddhist "Seven Treasures"—gold, crystal, lapis lazuli, and gemstones—employing dozens of traditional crafts including bronze casting, fire-gilding, cloisonné enamel, sculpture, and metal chasing. The blue finial portion of the pagoda, standing 2.8 meters tall, is crafted entirely in cloisonné enamel, making it one of the tallest and most intricate pagodas of its kind in the world. The hall is laid out according to the Five Directional Buddhas of the Avatamsaka realm, with the relic pagoda representing Vajradhatu Mahavairocana at its center, surrounded by the Four Paramita Bodhisattvas, the Four Directional Buddhas, the Sixteen Wisdom-Gate Vidyarajas, and the Eight Inner and Eight Outer Offering Bodhisattvas, together forming a three-dimensional rendering of the Fourth Offering Assembly of the Vajradhatu Mandala. On major Buddhist holidays, the usnisa bone relic is ceremonially escorted from the deepest relic chamber to the great pagoda for public veneration.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_niushoushan_sa_05.jpg', 4),
  ('nanjing_niushoushan_sa_06', 'nanjing_niushoushan', 'Usnisa Palace · Ten Thousand Buddha Corridor and Relic Hidden Chamber', '佛顶宫·万佛廊与舍利藏宫', 'The Ten Thousand Buddha Corridor encompasses the third, fourth, and fifth underground levels of the Usnisa Palace, forming a circular passageway around the exterior of the Thousand Buddha Hall. The third underground level focuses on Chinese Buddhist culture, featuring two sutra verse corridors and sixteen silk-mounted Gongbi paintings. The fourth level showcases Indian Buddhist culture, with statues of the Twenty Devas and seven lacquer paintings depicting Indian Buddhist teachings. The fifth level centers on the Buddha''s past-life stories (Jataka) and relic culture, including multimedia displays, ten porcelain paintings of the Sixteen Bodhisattvas of the Bhadrakalpa, and the Eight Great Stupas with related artifacts. The Relic Hidden Chamber (Sharicang Gong), located 44 meters below ground, is the deepest space in the Usnisa Palace and the permanent enshrinement site of the Buddha''s usnisa bone relic. The chamber is rendered in dark tones to create a solemn and mysterious atmosphere. Its 66-meter corridor is arranged according to the Six Paramitas (precepts, generosity, patience, diligence, meditation, and wisdom), and the central area serves as a consecrated religious hall where the relic is permanently enshrined.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_niushoushan_sa_06.jpg', 5),
  ('nanjing_niushoushan_sa_07', 'nanjing_niushoushan', 'Usnisa Pagoda', '佛顶塔', 'The Usnisa Pagoda stands atop the western peak of Niushou Mountain, above the Usnisa Palace, and is one of the iconic landmarks of the Usnisa Sacred Realm. Built in the Tang dynasty architectural style as an imitation-wood brick pagoda, it is octagonal with nine stories, rising approximately 88 meters to crown the western summit. The construction of the Usnisa Pagoda restored the historic "twin peaks, twin pagodas" panorama of Niushou Mountain—the new western pagoda now faces the centuries-old Hongjue Temple Pagoda on the eastern peak across the valley, recreating one of ancient Jinling''s most celebrated vistas. The pagoda features layered flying eaves, stacked bracket sets, and a graceful tapered silhouette. Visitors who climb to the top are rewarded with panoramic views of the Usnisa Palace, the forested mountains, and the Jinling landscape beyond. The pagoda''s interior houses Buddhist statues and scriptures, making it an ideal spot for sightseeing, worship, and prayer.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_niushoushan_sa_07.jpg', 6),
  ('nanjing_niushoushan_sa_08', 'nanjing_niushoushan', 'Niutou Chan Cultural Park (Hongjue Temple Pagoda)', '牛头禅文化园（弘觉寺塔）', 'The Niutou Chan Cultural Park was built on the site of the Hongjue Temple, the birthplace of the Niutou (Ox-Head) school of Chan Buddhism. The temple was first constructed in 503 CE during the Liang Dynasty under Emperor Wu of Liang, originally named Foku Temple and also known as Hongjue Temple. Its name was changed to Hongjue Temple during the Qing dynasty to avoid the naming taboo of Emperor Qianlong (Hongli). The temple was burned down by Japanese forces during the War of Resistance, leaving only the pagoda standing. The Hongjue Temple Pagoda, the park''s centerpiece, stands 45 meters tall with seven stories in an octagonal plan. It is an imitation-wood brick pagoda—the oldest surviving structure of its kind in the Nanjing area. In 1956, the pagoda''s underground chamber yielded a gilded Lamaist pagoda, a jade vase, a gold sleeping Buddha, and a celadon jar, among other precious artifacts. The gilded Lamaist pagoda is now one of the Nanjing Museum''s greatest treasures. In 1957, the pagoda was designated a Jiangsu Provincial Cultural Heritage Protection Unit. Over seventy visitor inscriptions from the Ming and Qing dynasties have been discovered on the pagoda walls, adding significant historical and archaeological value.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_niushoushan_sa_08.jpg', 7),
  ('nanjing_niushoushan_sa_09', 'nanjing_niushoushan', 'Zheng He Cultural Park', '郑和文化园', 'The Zheng He Cultural Park is located on the southwestern foothills of Niushou Mountain and is the burial site of Zheng He (1371–1433), the great navigator of the Ming dynasty. Originally surnamed Ma and courtesy-named Sanbao, Zheng He was born in Kunyang, Yunnan, and was of Hui ethnicity. He conducted seven maritime expeditions to the Western Seas over twenty-eight years, reaching more than thirty countries and regions across Asia and Africa—a monumental achievement in the history of world navigation. Zheng He died of illness in 1433 during his seventh voyage and was buried at Niushou Mountain. The park contains his tomb, built in traditional Hui Islamic style, with a stele erected before it. The park also houses a maritime cultural relics exhibition displaying historical artifacts, models, and archival materials related to Zheng He''s voyages, comprehensively presenting the life and achievements of this great navigator. It is an important destination for understanding Ming dynasty maritime history and the culture of the Maritime Silk Road.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_niushoushan_sa_09.jpg', 8),
  ('nanjing_niushoushan_sa_10', 'nanjing_niushoushan', 'Yue Fei''s Anti-Jin Rampart', '岳飞抗金故垒', 'The Yue Fei Anti-Jin Rampart is a historic site within the Niushou Mountain scenic area where the renowned Southern Song dynasty general Yue Fei stationed his troops to resist the Jin invasion. During the Jianyan era (1127–1130 CE), as Jin forces advanced southward, Yue Fei led his army to establish defensive positions at Niushou Mountain, constructing stone ramparts along the mountain ridges. The surviving rampart stretches approximately 200 meters, built from mountain stone. Despite over eight centuries of weathering, the outline and scale of the ancient military fortification remain discernible. Winding along the ridge, the rampart reflects the architectural wisdom of ancient mountain defense works. As an important historical relic, the site not only bears witness to the turbulent years of the Southern Song resistance against the Jin but also carries the heroic spirit of defending the nation. Visitors can touch the stone remains, imagine the fierce battles of the past, and feel the weight of history.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_niushoushan_sa_10.jpg', 9),
  ('nanjing_shijiu_lake_sa_01', 'nanjing_shijiu_lake', 'Xiangyang Village Dam Viewing Platform, Shiqiu Subdistrict', '石湫街道向阳村·大堤观景台', 'Xiangyang Village in Shiqiu Subdistrict is located on the northern shore of Shijiu Lake in Lishui District, Nanjing. It marks the northern entrance of the Shijiu Lake Grand Bridge and is a classic vantage point for admiring the lake''s famed "Mirror of the Sky." The dam viewing platform beside the village offers an unobstructed, panoramic view of the 12.6-kilometer bridge spanning the lake like a dragon resting on the water, with sky and lake merging into one. On clear days, the mirror-like surface reflects clouds and sunlight, creating the dreamlike "Mirror of the Sky" effect. At sunset, golden light shimmers across the water as trains cross the bridge in the distance—every shot is a masterpiece. From the dam, visitors can also watch boats pass and migratory birds soar overhead. Since stopping on the bridge is prohibited, the dam is the safest and most ideal viewing spot.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_shijiu_lake_sa_01.jpg', 0),
  ('nanjing_shijiu_lake_sa_02', 'nanjing_shijiu_lake', 'Shijiu Lake Grand Bridge · Water Train', '石臼湖特大桥·水上列车', 'The Shijiu Lake Grand Bridge stretches 12.6 kilometers, connecting Lishui and Gaochun districts in Nanjing. It carries both a highway and the Ninggao Intercity Rail Transit (Metro Line S9). When an S9 train crosses the lake on the bridge, the view from the carriage windows—where water and sky merge into one—creates the illusion of a train gliding over the sea, earning it the nicknames "Nanjing''s Sea Train" and "Water Train" among internet users. This unique transportation spectacle has drawn countless photographers who capture the train crossing the lake from various angles. Riding the S9 line is itself an unforgettable sightseeing experience: through the windows, the vast expanse of blue water, distant mountain silhouettes, and the horizon unfold in full. The bridge spans the lake from east to west, with the deck just meters above the water. When the lake is full, it feels like traveling on the open sea—most breathtaking in the misty early morning or under a sky blazing with sunset hues.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_shijiu_lake_sa_02.jpg', 1),
  ('nanjing_shijiu_lake_sa_03', 'nanjing_shijiu_lake', 'Xizhao Village Birdwatching Point, Honglan Subdistrict', '洪蓝街道西赵村·候鸟观测点', 'The Xizhao Village Birdwatching Point is located in Jiajia Xizhao Village, Honglan Subdistrict, Lishui District. It is a vital part of the Shijiu Lake wetlands and, thanks to its expansive open water, rich aquatic vegetation, and favorable ecological conditions, serves as a crucial habitat for migratory and wintering birds. Shijiu Lake is an important stopover on the migratory flyway. Survey data shows that 159 wild bird species across 16 orders and 44 families have been recorded in the area in recent years, including three species under national Class I protection—the Black-faced Spoonbill, Oriental White Stork, and Red-crowned Crane—and fourteen species under national Class II protection, including the Tundra Swan, Whooper Swan, Swan Goose, White Spoonbill, and Common Crane. Each year from autumn through early spring, flocks of swans and waterfowl arrive from Siberia and other northern regions to winter on the lake, creating a spectacular sight. The best birdwatching time is at dawn when mist lingers over the water and birdsong fills the air. Visitors are urged to observe birds responsibly—maintain distance, do not feed, and do not disturb.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_shijiu_lake_sa_03.jpg', 2),
  ('nanjing_shijiu_lake_sa_04', 'nanjing_shijiu_lake', 'First Work Zone · Lighthouse and the Lonely Tree', '一工区·灯塔与孤独的树', 'The First Work Zone is located on the Lishui-side shoreline of Shijiu Lake, named after the lake''s zoned management system. It has become an internet-famous photography destination in recent years. Two iconic landmarks define the area: a red-and-white lighthouse standing on the lakeshore, its clean lines and vivid colors making it a perfect compositional focal point against the blue water and sky; and a solitary tree standing alone in the shallow water, affectionately known as the "Lonely Tree." Through the seasons, the tree shifts from lush to bare, creating a minimalist and poetic image against the vast open lake. At sunset, the silhouettes of the lighthouse and the lonely tree against the evening glow are especially moving, drawing numerous photographers. The area features a winding shoreline, lush reed beds, and a beautiful ecological environment, making it a great spot for walking, cycling, and enjoying the lakeside wilderness. A nearby tree whose canopy naturally forms a heart shape—known as the "Heart Tree"—is another popular photo spot.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_shijiu_lake_sa_04.jpg', 3),
  ('nanjing_shijiu_lake_sa_05', 'nanjing_shijiu_lake', 'Zhangxu Village Sunset Pier, Hefeng Town', '和凤镇张许村·日落栈桥', 'Zhangxu Village in Hefeng Town is located on the southern shore of Shijiu Lake and is a classic vantage point for viewing the lake''s sunset and the "Water Train." A pier extends from the shore into the lake, and standing at its end opens up an unobstructed view of the boundless water where lake meets sky. The optimal visiting time is between 4:00 and 6:00 PM, when the setting sun casts golden light across the rippling surface and water merges with sky. If a Metro Line S9 train happens to cross the grand bridge at that moment, the composition of train and sunset creates an effortless masterpiece. From 7:00 to 8:00 AM, mist drifting over the lake lends a fairy-tale atmosphere. The pier area is rich in aquatic vegetation, and migratory birds occasionally appear, blending natural ecology with cultural scenery. Light-colored clothing is recommended for better photo results. The site has become a popular destination for photographers and travel bloggers alike.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_shijiu_lake_sa_05.jpg', 4),
  ('nanjing_shijiu_lake_sa_06', 'nanjing_shijiu_lake', 'Zhujia Village Ancient Village, Hefeng Town', '和凤镇诸家村·古村落', 'Zhujia Village in Hefeng Town sits on the southern shore of Shijiu Lake. It is a traditional ancient village built along the water, with whitewashed walls and dark-tiled-roof houses scattered organically along the shoreline, preserving the simple and tranquil character of a Jiangnan water-town village. The village has a long history, with residents who have fished and farmed for generations and maintained a simple, honest way of life. Strolling through the village, visitors encounter old houses, ancient wells, stone-paved paths, and lakeside vegetable gardens, with smoke rising from kitchen chimneys and the sounds of rural life—a scene reminiscent of an earthly paradise. The open lake before the village offers vast blue waters on sunny days and misty, poetic vistas in the rain, with scenery that shifts beautifully through the seasons. Adjacent to the Zhangxu Village sunset pier, Zhujia Village can be combined into a single itinerary linking cultural heritage with natural lakeside beauty. It is an ideal destination to experience the original lakeside lifestyle and enjoy a slow, pastoral pace. In recent years, as Shijiu Lake tourism has grown, the village has developed farm-stay restaurants and guesthouses, offering visitors rural cuisine and accommodation.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_shijiu_lake_sa_06.jpg', 5),
  ('nanjing_sun_yat_sen_mausoleum_sa_01', 'nanjing_sun_yat_sen_mausoleum', 'Xiaojing Ding Square', '孝经鼎广场', 'Xiaojing Ding Square serves as the starting point of the Sun Yat-sen Mausoleum scenic area. At its center stands a bronze tripod known as the Xiaojing Ding, cast in 1933 with funding from Dai Jitao and his mother. The tripod bears the full text of the Classic of Filial Piety, hence its name. Standing approximately 4.25 meters tall and weighing five tons, it features an elegant and solemn design. Surrounded by lush pines and cypresses, the square offers a tranquil setting and serves as the first stop for visitors, providing a sweeping view of Purple Mountain.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_sun_yat_sen_mausoleum_sa_01.jpg', 0),
  ('nanjing_sun_yat_sen_mausoleum_sa_02', 'nanjing_sun_yat_sen_mausoleum', 'Bo''ai Archway', '博爱坊', 'The Bo''ai Archway serves as the southern entrance gateway to the Sun Yat-sen Mausoleum. Constructed between 1929 and 1931 from granite, it features a four-pillar, three-arch design imitating traditional wooden structure. The central lintel bears Dr. Sun Yat-sen''s own calligraphy of "Bo''ai" (Universal Love) in gilded characters, embodying his philosophy of universal love. Standing 12 meters tall and 17 meters wide, the archway is grand and imposing. It is the most important landmark marking the entrance to the mausoleum area and a classic photo spot for visitors.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_sun_yat_sen_mausoleum_sa_02.jpg', 1),
  ('nanjing_sun_yat_sen_mausoleum_sa_03', 'nanjing_sun_yat_sen_mausoleum', 'Sacred Way', '墓道', 'The Sacred Way is the long promenade between the Bo''ai Archway and the Mausoleum Gate, extending approximately 480 meters in length and 40 meters in width, paved with granite. Rows of pines and cypresses line both sides, remaining verdant year-round and creating a solemn atmosphere. The way is divided into three paths — a central main path flanked by two side paths — symbolizing the cosmos revolving around the moon. A semi-circular plaza midway along the way can accommodate large gatherings. The design reflects traditional Chinese mausoleum protocol and profound reverence for Dr. Sun Yat-sen.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_sun_yat_sen_mausoleum_sa_03.jpg', 2),
  ('nanjing_sun_yat_sen_mausoleum_sa_04', 'nanjing_sun_yat_sen_mausoleum', 'Mausoleum Gate', '陵门', 'The Mausoleum Gate, built in 1929, is the core portal of the Sun Yat-sen Mausoleum in the style of Ming and Qing palace architecture. It spans five bays wide and three bays deep, constructed of granite and topped with blue-glazed tiles. The central lintel bears four gilded characters in Dr. Sun''s calligraphy: "Tian Xia Wei Gong" (The World Belongs to All). The gate has three arched entrances; the central one is normally closed and opened only for major commemorative events. A pair of stone lions flanks each side. Broad platforms on both the north and south sides offer panoramic mountain views.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_sun_yat_sen_mausoleum_sa_04.jpg', 3),
  ('nanjing_sun_yat_sen_mausoleum_sa_05', 'nanjing_sun_yat_sen_mausoleum', 'Stele Pavilion', '碑亭', 'The Stele Pavilion stands between the Mausoleum Gate and the stone steps. Built in 1929, it is a square stone structure topped with blue-glazed tiles. At its center rises a giant granite stele approximately 9 meters tall, its front inscribed with 24 gilded characters reading: "The Chinese Nationalist Party buried Prime Minister Sun here on June 1, 1929," calligraphed by Tan Yankai. The stele rests on an elaborately carved sumeru base. Notably, the stele records only the burial event without any eulogistic text, signifying that Dr. Sun''s contributions are beyond written description. The pavilion is a key architectural landmark along the sacred way.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_sun_yat_sen_mausoleum_sa_05.jpg', 4),
  ('nanjing_sun_yat_sen_mausoleum_sa_06', 'nanjing_sun_yat_sen_mausoleum', 'Stone Steps', '石阶', 'The Stone Steps connect the Stele Pavilion to the Sacrificial Hall, built from granite with a total of 392 steps symbolizing China''s 392 million compatriots at the time. Divided into ten sections of increasing steepness, the steps create a brilliant optical illusion: looking up from the bottom, only steps are visible; looking down from the top, only platforms appear. Eight rest platforms are interspersed along the way, flanked by deodar cedars and southern magnolias. Climbing the steps is both a physical challenge and a spiritual journey, symbolizing a solemn pilgrimage to honor the great man. The summit offers panoramic views of Nanjing.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_sun_yat_sen_mausoleum_sa_06.jpg', 5),
  ('nanjing_sun_yat_sen_mausoleum_sa_07', 'nanjing_sun_yat_sen_mausoleum', 'Sacrificial Hall', '祭堂', 'The Sacrificial Hall is the core building of the Sun Yat-sen Mausoleum, designed by renowned architect Lü Yanzhi and completed in 1929. This palace-style structure stands approximately 29 meters tall, 39 meters long, and 27 meters wide, constructed of granite and reinforced concrete with a blue-glazed tile roof. At its center is a white marble seated statue of Dr. Sun, sculpted by French artist Paul Landowski, standing 4.6 meters tall with relief carvings on its base depicting his revolutionary deeds. The walls are inscribed with the full text of his Fundamentals of National Reconstruction, his Strategies for National Development, and his political testament. The coffered ceiling features exquisite painted decoration.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_sun_yat_sen_mausoleum_sa_07.jpg', 6),
  ('nanjing_sun_yat_sen_mausoleum_sa_08', 'nanjing_sun_yat_sen_mausoleum', 'Coffin Chamber', '墓室', 'The Coffin Chamber lies behind the Sacrificial Hall and is the most sacred space within the mausoleum, completed in 1929. It features a hemispherical dome approximately 18 meters in diameter and 11 meters in height, with marble flooring throughout. At its center is Dr. Sun''s tomb, surmounted by a white marble reclining statue sculpted by Czech artist Bohuslav Koci, remarkably lifelike in detail. Dr. Sun''s sarcophagus rests directly beneath the statue. Railings surround the tomb, allowing visitors to walk around and pay their respects. The dim, solemn atmosphere makes this the most important site for honoring Dr. Sun''s memory. The chamber is closed on Mondays for preservation purposes.', '', 7),
  ('nanjing_sun_yat_sen_mausoleum_sa_09', 'nanjing_sun_yat_sen_mausoleum', 'Music Stage and Ancillary Buildings', '音乐台与附属建筑', 'The Music Stage is located on the southeast side of the mausoleum square, designed by Guan Songsheng and Yang Tingbao and constructed between 1932 and 1933. This semicircular open-air theater draws inspiration from ancient Greek amphitheaters while incorporating traditional Chinese architectural elements. The stage''s crescent-shaped backdrop wall stands approximately 11 meters tall and 30 meters wide, decorated with cloud and fretwork patterns. The audience area is a semicircular lawn accommodating about 3,000 people, encircled by a crescent colonnade and wisteria pergolas. A lotus pond in front of the stage creates a harmonious interplay of water and architecture. The stage remains an active cultural venue hosting concerts and events year-round. Nearby ancillary buildings include Xingjian Pavilion, Guanghua Pavilion, and Yangzhi Pavilion.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_sun_yat_sen_mausoleum_sa_09.jpg', 8),
  ('nanjing_presidential_palace_sa_01', 'nanjing_presidential_palace', 'Gate Tower', '门楼', 'The Gate Tower is the iconic entrance of the Nanjing Presidential Palace, built in 1929 by Yao Xizhou''s construction firm. This brick-and-concrete structure spans three bays and features Western classical column design, with eight Ionic columns on its facade creating an imposing presence. The tower originally displayed a plaque reading "National Government," replaced with "Presidential Palace" in 1948. Standing approximately 10 meters tall with flanking guard rooms, the gate combines Chinese and Western architectural elements in an elegant and dignified design. The square in front witnessed numerous major historical events, including the planting of the red flag on April 24, 1949, marking the transition of power.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_presidential_palace_sa_01.jpg', 0),
  ('nanjing_presidential_palace_sa_02', 'nanjing_presidential_palace', 'Guard Rooms and Main Hall', '朝房与大堂', 'Upon passing through the Gate Tower, the flanking Guard Rooms originally served as duty stations for guards and aides and now house exhibition spaces. A spacious corridor between them leads to the Main Hall. The hall originally served as the principal hall of the Taiping Heavenly Kingdom''s palace, later as the main hall of the Qing Governor''s office, and during the National Government era as a venue for important meetings and receptions. This seven-bay building with a flush gable roof features a lofty, solemn interior. A plaque with Dr. Sun Yat-sen''s calligraphy "The World Belongs to All" hangs at the center.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_presidential_palace_sa_02.jpg', 1),
  ('nanjing_presidential_palace_sa_03', 'nanjing_presidential_palace', 'Second Hall and Bashiting Hall', '二堂与八字厅', 'The Second Hall sits behind the Main Hall as the second building along the central axis, originally part of the Qing Governor''s office and Taiping palace. This five-bay hall blends Chinese and Western interior decoration and served as the formal reception room for the National Government chairman and president. Behind it lies Bashiting Hall, named after the splayed walls flanking its entrance that form the Chinese character "ba" (eight). This Sino-Western hybrid building features a spacious, well-lit interior and was used for important diplomatic receptions and ceremonial events. A courtyard connects the two halls, creating a layered spatial sequence. Decorative details retain historical traces from different periods.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_presidential_palace_sa_03.jpg', 2),
  ('nanjing_presidential_palace_sa_04', 'nanjing_presidential_palace', 'Qilin Gate and Bureau of Government Affairs Building', '麒麟门与政务局大楼', 'Qilin Gate is a key node on the central axis of the Presidential Palace — a screen-style gate named for the qilin (mythical beast) relief embedded above its lintel. In Chinese culture, the qilin symbolizes auspiciousness and benevolence, and its placement here signifies national peace and prosperity. The gate was normally closed, opened only for distinguished guests, serving as a visual screen and ceremonial boundary. Beyond it stands the Bureau of Government Affairs Building, a three-story Western-style structure built during the Republican era that housed the bureau''s offices. The interior preserves original office layouts and furnishings, illustrating the administrative operations of the National Government.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_presidential_palace_sa_04.jpg', 3),
  ('nanjing_presidential_palace_sa_05', 'nanjing_presidential_palace', 'Zichao Building and Presidential Office', '子超楼及总统办公室', 'Zichao Building stands at the northernmost end of the central axis, built in 1934 and named after National Government Chairman Lin Sen (courtesy name Zichao), who initiated its construction. This three-story Sino-Western hybrid building features brown brick facing and a clean, dignified design. The first floor housed the Bureau of Documents, the second floor contained the offices of the Secretary-General and the Aide-de-Camp General, and the third floor held Chiang Kai-shek''s presidential office. The office preserves original furnishings including the desk, filing cabinets, and sofa, with photographs and maps of Chiang on the walls. Windows offer views of Xuyuan Garden to the west.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_presidential_palace_sa_05.jpg', 4),
  ('nanjing_presidential_palace_sa_06', 'nanjing_presidential_palace', 'Fuyuan Garden', '复园', 'Fuyuan Garden is located on the east side of the Presidential Palace, rebuilt on the site of the East Garden of the Qing Governor''s office. Centered on water features, the garden features pavilions, terraces, towers, and winding corridors arranged in a typical Jiangnan private garden style. Key sights include Wangfei Pavilion, Yilan Pavilion, and Tongyin Hall, with elegant architecture complemented by flowers, trees, water, and rockery. The garden was part of the Taiping Heavenly Kingdom''s palace before being damaged in war, and has been restored based on historical records. Exhibitions on the Qing Governor''s office history are displayed within. The garden offers distinct seasonal beauty year-round.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_presidential_palace_sa_06.jpg', 5),
  ('nanjing_presidential_palace_sa_07', 'nanjing_presidential_palace', 'Exhibition on the Qing Governor-General''s Office', '清两江总督署史料展', 'The Exhibition on the Qing Governor-General''s Office is housed in the western axis complex of the Presidential Palace and is the first systematic exhibition on this topic in China. The Governor-General of Liangjiang governed Jiangsu, Anhui, and Jiangxi provinces, making it one of the most important regional officials of the Qing Dynasty. Through extensive historical documents, photographs, artifacts, and scene reconstructions, the exhibition comprehensively presents the establishment, evolution, notable governors, and major events over more than 200 years from the Kangxi era to the Xuantong era. Renowned officials including Lin Zexu, Zeng Guofan, Li Hongzhang, Zuo Zongtang, and Zhang Zhidong served here. The exhibition is a vital window into Qing-era Jiangnan political history.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_presidential_palace_sa_07.jpg', 6),
  ('nanjing_presidential_palace_sa_08', 'nanjing_presidential_palace', 'Exhibition of the Taiping Heavenly Kingdom Palace', '太平天国天朝宫殿陈列', 'The Exhibition of the Taiping Heavenly Kingdom Palace is housed in the central axis complex of the Presidential Palace, on the very site of the original Taiping palace. After the Taiping army captured Nanjing in 1853, Hong Xiuquan built the grand Heavenly Kingdom Palace (also called the Heavenly King''s Palace) here. The palace was destroyed when Xiang Army forces took Nanjing in 1864, and existing buildings were later reconstructed. Through artifacts, models, images, and multimedia, the exhibition presents the 14-year history of the Taiping Heavenly Kingdom from the 1851 Jintian Uprising to the 1864 fall of Nanjing. Displays include a reconstruction model of the palace, Taiping relics, and historical documents.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_presidential_palace_sa_08.jpg', 7),
  ('nanjing_presidential_palace_sa_09', 'nanjing_presidential_palace', 'Executive Yuan', '行政院', 'The Executive Yuan is located in the western part of the Presidential Palace and served as the office of the National Government''s Executive Yuan. Established in 1928 as one of the five Yuans of the National Government, it was the nation''s highest executive organ. The surviving buildings date from the 1930s, comprising a courtyard complex with a main building and auxiliary wings. The three-story Western-style main building features classical design elements with meticulously crafted colonnades and moldings. The interior preserves original meeting rooms and offices, and houses a special exhibition on the Executive Yuan''s organizational structure, successive presidents, and major decisions. It is an important resource for studying Republican-era government architecture and administrative systems.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_presidential_palace_sa_09.jpg', 8),
  ('nanjing_presidential_palace_sa_10', 'nanjing_presidential_palace', 'Xuyuan Garden', '煦园', 'Xuyuan Garden, situated on the west side of the Presidential Palace, is a celebrated classical Jiangnan garden originating from the Ming Dynasty. Originally the garden of the Ming Prince of Han''s mansion, it was cultivated through successive periods — the Qing Governor''s office, Taiping Heavenly Kingdom palace, and Republican Presidential Palace — developing a unique blend of Ming and Qing garden styles. The garden centers on water features, with Taiping Lake at its middle reflecting surrounding pavilions and towers. Key sights include Buxizhou (Unmoored Boat), Yilan Pavilion, Xijia Tower, Wangfei Pavilion, and Yixin Stone House, with elegant architecture interspersed with rockeries and sculptural stones. Historical relics including stone steles inscribed by Dr. Sun Yat-sen are preserved here.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_presidential_palace_sa_10.jpg', 9),
  ('nanjing_presidential_palace_sa_11', 'nanjing_presidential_palace', 'Taiping Lake and Buxizhou (Unmoored Boat)', '太平湖与不系舟', 'Taiping Lake is the central water feature of Xuyuan Garden, narrow from east to west with mirror-like surface reflecting surrounding pavilions, towers, ancient trees, and floral shadows. Xijia Tower stands on the north shore, Yilan Pavilion on the south, connected by zigzag bridges and corridors to form a perfect Jiangnan garden tableau. East of center in the lake sits a stone boat named Buxizhou (Unmoored Boat), carved from blue stone in the shape of a wooden vessel, its bow pointing east as if ready to set sail. Built by Qing Governor-General Yin Jishan, the boat was named by Emperor Qianlong during his southern tour, drawn from Zhuangzi''s phrase "drifting like an unmoored boat." The exquisitely designed stone boat is the most poetic sight in Xuyuan Garden.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_presidential_palace_sa_11.jpg', 10),
  ('nanjing_presidential_palace_sa_12', 'nanjing_presidential_palace', 'Office of Sun Yat-sen as Provisional President', '孙中山临时大总统办公室', 'The Office of Sun Yat-sen as Provisional President is located on the west side of Xuyuan Garden in a Western-style bungalow built in 1910. On January 1, 1912, Dr. Sun was sworn in here as the Provisional President of the Republic of China, marking the end of over two millennia of imperial rule and the birth of Asia''s first democratic republic. The interior has been restored to its original appearance, including Dr. Sun''s desk, chairs, filing cabinets, and reception area furniture. Reproductions of provisional government documents and appointment orders signed by Dr. Sun are on display. The building features a yellow exterior with a red tile roof. A nearby exhibition on Dr. Sun''s life makes this an important site for commemorating the Xinhai Revolution and the founding of the Republic.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_presidential_palace_sa_12.jpg', 11),
  ('nanjing_presidential_palace_sa_13', 'nanjing_presidential_palace', 'Sun Yat-sen''s Residence', '孙中山起居室', 'Sun Yat-sen''s Residence is located within Xuyuan Garden and served as Dr. Sun''s living quarters during his tenure as Provisional President of the Republic of China in 1912. The building is a two-story Chinese-style structure of brick and wood with grey tiles and white walls — modest and elegant, contrasting with the Western style of his office. The first floor contains a parlor and study, while the second floor holds bedrooms and staff rooms. The interior displays furniture, clothing, and personal items used by Dr. Sun and his family, recreating the living scene of the era. A small courtyard in front with osmanthus and magnolia trees provides a tranquil setting. The residence reflects Dr. Sun''s frugal and simple lifestyle, offering an intimate window into his personal life and character.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/nanjing_presidential_palace_sa_13.jpg', 12)
